INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_001', '肺炎', 'Pneumonia', 'Pneumonia', '["呼吸系统"]', '["犬", "猫"]', '呼吸系统', '感染性', '犬细菌性肺炎多发于幼犬及老年犬，尤其是免疫抑制个体；任何品种均可发病，短头品种风险略高。吸入性肺炎常见于灌食不当或食管疾病患犬。无明显季节性，但冬季因呼吸道感染高发而间接增加发病率。免疫功能低下动物全年均可发病。', '肺部炎症反应，可由细菌、病毒、真菌或吸入性因素引起。犬最常见为细菌性肺炎，猫多为吸入性或病毒性。', '["细菌感染(博德特氏菌、链球菌)", "病毒感染", "真菌感染", "吸入性因素"]', '病原体入侵肺泡后炎症介质释放，中性粒细胞浸润，肺泡充满渗出液导致气体交换障碍和低氧血症。', '病原体（细菌、病毒、真菌或吸入物）突破呼吸道防御机制后侵入肺泡，激活固有免疫反应。中性粒细胞和巨噬细胞募集至感染部位，释放促炎因子（IL-1、IL-6、TNF-α），导致肺泡毛细血管通透性增加，富含蛋白质的渗出液和中性粒细胞充填肺泡腔。肺实变区域气体交换面积减少，通气/血流比例失调，引起低氧血症。严重者可并发脓胸或急性呼吸窘迫综合征（ARDS）。', '早期治疗预后良好。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_002', '心力衰竭(犬)', 'CHF', 'Insufficiencia cordis', '["心血管系统"]', '["犬"]', '心血管系统', '退行性', '最常见于中老年小型犬，黏液样二尖瓣退化（MMVD）在骑士查理王小猎犬、迷你贵宾犬、腊肠犬等品种中有显著遗传倾向。扩张型心肌病（DCM）多见于大型犬，如杜宾犬、大丹犬和拳师犬，公犬发病率高于母犬。一般发病年龄为5岁以上，随年龄增长发病率显著升高。无明显季节性。', '心脏泵血功能不足以满足机体代谢需求，导致肺循环和/或体循环淤血。最常见病因是黏液样二尖瓣退化(MMVD)。', '["MMVD", "DCM", "先天性心脏病"]', '瓣膜关闭不全导致血液反流，心房压力升高导致肺静脉压升高引发肺水肿。', 'MMVD导致二尖瓣叶增厚变形，收缩期无法完全闭合，血液从左心室反流至左心房。左心房容量负荷增加导致扩张，肺静脉回流受阻，肺毛细血管静水压升高。当肺毛细血管楔压超过血浆胶体渗透压（约25 mmHg）时，液体渗入肺泡腔形成肺水肿。同时，心输出量下降激活肾素-血管紧张素-醛固酮系统（RAAS），导致水钠潴留、前负荷进一步增加，形成恶性神经体液循环。长期代偿性心肌肥厚最终导致心肌纤维化和收缩功能下降。', '取决于病因和控制程度。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_003', '猫哮喘', 'Feline Asthma', 'Asthma felinum', '["呼吸系统"]', '["猫"]', '呼吸系统', '免疫介导性', '猫哮喘多发于2-8岁中年猫，暹罗猫及其杂交品种有遗传易感性，母猫发病率略高于公猫。环境因素如粉尘、烟雾、花粉和猫砂粉尘是常见诱因。无明显季节性，但春季花粉季节和冬季室内通风不良时发作频率可能增加。全球发病率约为1-5%，实际发病率可能因漏诊而被低估。', '猫下呼吸道慢性炎症性疾病，特征为气道高反应性和可逆性气流受限。', '["过敏原(尘螨、花粉、烟雾)", "环境刺激物", "应激", "特发性"]', 'IgE介导的I型超敏反应，肥大细胞脱颗粒，嗜酸性粒细胞浸润导致气道平滑肌收缩和黏膜水肿。', '过敏原经呼吸道进入后，被树突状细胞呈递给Th2淋巴细胞，刺激B细胞产生特异性IgE。IgE与肥大细胞表面FcεRI受体结合，再次接触过敏原时发生交联，触发肥大细胞脱颗粒，释放组胺、白三烯、前列腺素D2等预存介质。这些介质导致急性支气管平滑肌痉挛、黏膜水肿和黏液分泌增加。同时，趋化因子招募嗜酸性粒细胞、淋巴细胞至气道壁，释放主要碱性蛋白（MBP）和嗜酸性粒细胞阳离子蛋白（ECP），损伤气道上皮。慢性炎症导致气道重塑：基底膜增厚、平滑肌增生和杯状细胞化生，造成不可逆性气流受限。', '需终身管理，多数猫经治疗可正常生活。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_004', '气管塌陷', 'Tracheal Collapse', 'Collapsus tracheae', '["呼吸系统"]', '["犬"]', '呼吸系统', '退行性', '主要发生于小型犬，约克夏梗、博美犬、贵宾犬、吉娃娃和马尔济斯犬等品种有明确的遗传倾向。多发于中老年犬（6岁以上），但部分易感品种可在2-3岁即出现症状。肥胖是重要的加重因素。无明显季节性和性别差异，但高温高湿环境可加重呼吸困难症状。', '气管软骨环变平、气管膜松弛导致气管腔狭窄，多见于小型犬。特征性表现为阵发性鹅叫样咳嗽。', '["遗传倾向(贵宾、约克夏)", "肥胖", "老年退行性变"]', '软骨结构异常导致吸气时气管塌陷气流受阻而咳嗽。', '气管软骨环的软骨基质发生退行性变性，糖胺聚糖含量减少，软骨细胞萎缩，导致软骨环机械强度下降、变平。同时气管膜（气管肌和结缔组织）松弛冗余。吸气时胸腔负压增大，使膜部向气管腔内膨出，管腔面积缩小；呼气时胸腔正压使已经变扁的软骨环进一步塌陷。气流通过狭窄气道时产生湍流，刺激黏膜感受器引发特征性鹅叫样咳嗽。慢性刺激导致气管黏膜继发性炎症、水肿和黏液分泌增加，进一步加重气道狭窄，形成恶性循环。', '控制症状为主，无法根治。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_005', '急性肾损伤', 'AKI', 'Insufficiencia renalis acuta', '["泌尿系统", "急诊"]', '["犬", "猫"]', '泌尿系统', '中毒性', '任何年龄、品种和性别的动物均可发生。乙二醇中毒多见于冬季（防冻液使用季节），有地区性分布特点。钩端螺旋体病多发于温暖潮湿季节，与鼠类接触史密切相关，公犬因嗅闻行为暴露风险更高。NSAIDs相关AKI多见于老年犬和已有肾功能减退的个体。尿路梗阻性AKI公猫因尿道狭窄更易发生。', '肾功能急剧下降，表现为氮质血症、少尿/无尿和电解质紊乱。', '["缺血(脱水、休克)", "肾毒性药物(NSAIDs、乙二醇)", "钩端螺旋体病", "尿路梗阻"]', '肾血流下降或肾毒性因素导致肾小管上皮细胞坏死，GFR下降导致代谢废物蓄积。', '缺血性AKI时，有效循环血量下降导致肾血流减少，入球小动脉收缩，肾小球滤过率（GFR）急剧下降。肾小管上皮细胞（尤其是近端小管S3段和髓袢升支粗段）对缺氧极为敏感，发生细胞肿胀、刷状缘脱落和细胞凋亡/坏死。毒性物质（如乙二醇代谢产物草酸钙结晶、庆大霉素）直接损伤肾小管上皮细胞线粒体和溶酶体。坏死的细胞脱落形成管型堵塞肾小管，肾小管内压升高进一步降低GFR。同时，受损内皮细胞释放内皮素和一氧化氮失衡，加重肾血管收缩。如损伤持续，可进展为急性肾小管坏死（ATN），基底膜破坏后再生修复困难。', '早期干预可逆，延误则可能进展为CKD或死亡。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_006', '慢性肾病', 'CKD', 'Morbus renalis chronicus', '["泌尿系统"]', '["犬", "猫"]', '泌尿系统', '退行性', '是老年猫最常见的疾病之一，15岁以上猫发病率超过30%，猫平均发病年龄为9-10岁。犬的发病率随年龄增长而升高，7岁以上犬风险显著增加。某些品种有遗传倾向：猫中的阿比西尼亚猫和波斯猫易患多囊肾；犬中的伯恩山犬易患肾小球肾炎。公猫因尿道问题继发肾后性CKD风险略高。无明显季节性。', '肾功能进行性和不可逆性丧失，是老年猫最常见的疾病之一。', '["特发性肾小管间质性肾炎", "肾淀粉样变(猫)", "多囊肾(猫)", "既往AKI后遗症"]', '肾单位逐渐丢失，残余肾单位高滤过导致进一步损伤和纤维化。', '各种原发性肾损伤（免疫介导性肾小球肾炎、间质性肾炎、肾淀粉样变等）导致功能性肾单位逐渐丢失。残余肾单位代偿性高滤过，肾小球毛细血管内压升高，蛋白滤过增加。滤过的蛋白质在近端小管重吸收后激活溶酶体通路，释放促炎和促纤维化因子。同时，肾小球高压导致足细胞损伤和基底膜增厚，最终肾小球硬化。肾小管间质纤维化是各种CKD的共同终末通路：成纤维细胞活化增殖，细胞外基质过度沉积，肾小管萎缩。纤维化区域缺氧进一步刺激促纤维化因子（TGF-β）释放，形成不可逆的恶性循环。', '不可逆，但早期干预可显著延长生存期。', 'advanced', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_007', '尿路感染', 'UTI', 'Infectio tractus urinarii', '["泌尿系统"]', '["犬", "猫"]', '泌尿系统', '细菌性', '犬的发病率显著高于猫。母犬因尿道短而宽，细菌上行感染风险高于公犬。老年动物、糖尿病患犬、长期使用糖皮质激素或免疫抑制剂的动物发病率升高。英国可卡犬、德国牧羊犬等品种有易感性。无明显季节性，但夏季因饮水量变化可能影响发病率。约14%的犬在其一生中至少发生一次UTI。', '细菌侵入泌尿道并定植繁殖引起的炎症。犬较猫常见。', '["大肠杆菌(最常见)", "葡萄球菌", "逆行性上行感染"]', '细菌经尿道口上行在膀胱黏膜定植引发炎症反应。', '致病菌（最常见为大肠杆菌，占50%以上；其次为葡萄球菌、变形杆菌、肠球菌等）经尿道口逆行上行至膀胱。细菌通过菌毛黏附于尿路上皮细胞表面的甘露糖受体，逃避尿液冲刷的清除机制。定植后细菌繁殖，释放内毒素和溶血素，激活尿路上皮细胞Toll样受体（TLR4），触发NF-κB信号通路，释放IL-6、IL-8等趋化因子，募集中性粒细胞至感染部位。中性粒细胞浸润导致局部炎症反应，黏膜充血水肿，严重者形成黏膜溃疡。如感染沿输尿管逆行至肾脏，可引发肾盂肾炎，导致肾实质脓肿和瘢痕形成。', '单纯性UTI抗生素治疗预后极好。', 'basic', 1);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_008', '猫下尿路疾病', 'FLUTD', 'Dysuria tractus urinarii felinum', '["泌尿系统"]', '["猫"]', '泌尿系统', '特发性', '多发于2-6岁中年猫，肥胖猫、室内饲养猫和运动不足猫的发病率显著升高。波斯猫和异国短毛猫有品种倾向。公猫因尿道细长弯曲，尿道梗阻风险远高于母猫。多猫家庭中的猫因社交应激发病率更高。冬季和换季时因活动减少、饮水量变化，发作频率可能增加。约5-10%的猫会反复发作。', '猫下泌尿道疾病的总称，包括特发性膀胱炎(最常见)、尿结石、尿道梗阻等。', '["特发性膀胱炎(FIC)", "鸟粪石/草酸钙结石", "尿道痉挛", "应激"]', '应激导致交感神经激活，膀胱黏膜通透性增加，钾离子渗入组织层刺激C纤维导致疼痛。', '猫特发性膀胱炎（FIC，占FLUTD病例60%以上）的核心机制是应激-神经内分泌-膀胱轴功能紊乱。应激激活下丘脑-垂体-肾上腺轴（HPA轴）和交感神经系统，儿茶酚胺释放增加，膀胱壁血管收缩导致黏膜缺血。同时，糖胺聚糖（GAG）层缺损使尿液中的钾离子和有害物质渗透至膀胱壁深层，激活C纤维伤害性感受器，释放P物质和降钙素基因相关肽（CGRP），引发神经源性炎症。膀胱逼尿肌和尿道平滑肌痉挛导致排尿困难和尿频。公猫可因尿道痉挛和黏液栓或结晶形成完全梗阻，引起急性肾后性氮质血症和危及生命的电解质紊乱（高钾血症）。', 'FIC易复发，尿道梗阻为急症。', 'intermediate', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_009', '胰腺炎', 'Pancreatitis', 'Pancreatitis', '["消化系统"]', '["犬", "猫"]', '消化系统', '特发性', '犬多发于中老年、肥胖犬，迷你雪纳瑞、约克夏梗和可卡犬有品种倾向（可能与高甘油三酯血症相关）。猫多为特发性，常与炎症性胆管炎、IBD组成三联征。犬发病与高脂饮食密切相关，节假日前后因人类食物摄入增加而出现发病高峰。母犬发病率略高于公犬。无明显品种和性别差异（猫）。', '胰腺的炎症性疾病。犬多与高脂饮食有关，猫多为特发性或继发于IBD。', '["高脂饮食/高甘油三酯血症", "药物(化疗药)", "创伤", "特发性(猫)"]', '胰酶在胰腺内提前激活导致自身消化，炎症介质释放引发全身炎症反应。', '胰腺腺泡细胞内的胰蛋白酶原在病理条件下被异常激活为胰蛋白酶（正常情况下在十二指肠由肠激酶激活），触发所有消化酶原的级联激活。活化的磷脂酶A2破坏细胞膜磷脂层，弹性蛋白酶溶解血管壁弹性纤维，脂肪酶分解脂肪细胞。胰腺自身消化导致腺泡细胞坏死、脂肪皂化和出血。损伤相关分子模式（DAMPs）释放，激活Toll样受体和NLRP3炎症小体，大量释放IL-1β、IL-6、TNF-α等促炎因子，触发全身炎症反应综合征（SIRS）。炎症介质进入体循环可导致多器官功能障碍：急性呼吸窘迫综合征、弥散性血管内凝血（DIC）和急性肾损伤。', '轻度预后良好，重症坏死性胰腺炎死亡率30-50%。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_010', '胃肠炎', 'Gastroenteritis', 'Gastroenteritis', '["消化系统"]', '["犬", "猫"]', '消化系统', '感染性', '各年龄段的犬猫均可发病，但幼龄动物（小于6月龄）因免疫系统未成熟而发病率和死亡率更高。未免疫幼犬感染犬细小病毒（CPV-2）风险极高。饮食不当相关的胃肠炎在犬中更为常见（犬的杂食性和异食癖倾向）。寄生虫性胃肠炎在散养和群养动物中更常见。无明显品种倾向，但免疫缺陷品种（如罗威纳犬对CPV-2易感）风险更高。', '胃和/或肠道的炎症，是最常见的消化系统主诉之一。', '["饮食不当/食物变质", "细菌(沙门氏菌)", "病毒(细小、冠状病毒)", "寄生虫"]', '病原体或刺激物损伤胃肠黏膜导致炎症反应，黏膜屏障破坏导致水电解质分泌异常。', '病原体（病毒、细菌、寄生虫）或刺激物（变质食物、化学毒物）破坏胃肠道黏膜屏障。病毒（如CPV-2）直接感染和溶解快速分裂的肠隐窝上皮细胞，导致肠绒毛萎缩、吸收面积锐减。细菌（如沙门氏菌、产气荚膜梭菌）通过侵袭肠黏膜或释放肠毒素，刺激肠上皮细胞氯离子和水分大量分泌进入肠腔。黏膜屏障破坏后，肠道通透性增加，细菌和内毒素移位进入门静脉循环，激活库普弗细胞释放炎症介质。肠道神经系统参与调节：5-羟色胺（5-HT）从肠嗜铬细胞释放，激活迷走神经传入纤维引发呕吐反射。炎症介质和肠毒素刺激化学感受器触发区（CTZ），加重呕吐和腹泻。', '单纯性预后极好，病毒性细小未免疫幼犬死亡率可达91%。', 'basic', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_011', '异物梗阻', 'Foreign Body', 'Corpus alienum / Foreign body obstruction', '["消化系统", "外科"]', '["犬", "猫"]', '消化系统', '外伤性', '犬发病率显著高于猫，幼犬和青年犬因好奇心强、异食癖倾向更高发。无显著性别差异。犬多见骨性异物和线性异物，猫多见毛球和绳线异物。全年可发，无明确季节性。', '异物滞留消化道导致机械性梗阻。犬更常见。', '["玩具、骨头、袜子", "毛球(猫)", "线性异物(绳线，猫特有)"]', '异物嵌顿导致局部压迫，静脉回流受阻后动脉供血障碍导致肠壁缺血坏死。', '异物嵌顿于消化道狭窄部位（如幽门、十二指肠、回盲瓣），首先压迫肠壁导致静脉回流受阻，肠壁充血水肿；随后动脉供血障碍引发肠壁缺血、缺氧性损伤，最终可致肠壁坏死穿孔。线性异物可导致肠管折叠、皱缩，加速缺血进程。局部炎症反应释放组胺、前列腺素等介质，加重水肿和疼痛。', '早期取出预后好，穿孔后并发症风险高。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_012', '肝衰竭', 'Liver Failure', 'Hepatic insufficiency / Liver failure', '["消化系统"]', '["犬", "猫"]', '消化系统', '中毒性', '犬猫均可发病，犬因对乙酰氨基酚、木糖醇等肝毒性物质暴露风险更高。猫因缺乏葡萄糖醛酸转移酶对药物性肝损伤更敏感。急性肝衰竭无品种偏好，慢性肝病多见于中老年犬。无明确季节性，但毒素暴露相关病例在节假日期间可能增多。', '肝脏功能严重受损，可分为急性肝衰竭和慢性肝病终末期。', '["药物/毒素(对乙酰氨基酚-猫、木糖醇-犬)", "感染(钩端螺旋体、FIP)", "肿瘤"]', '大量肝细胞坏死导致解毒功能下降(高氨血症)、合成功能下降(低白蛋白)、胆汁排泄障碍(黄疸)。', '大量肝细胞坏死或功能障碍导致三大核心病理生理改变：一是解毒功能下降，氨等毒性物质蓄积引发肝性脑病；二是合成功能下降，白蛋白、凝血因子合成减少导致低白蛋白血症和凝血障碍；三是胆汁排泄障碍，胆红素蓄积引发黄疸。同时肝糖原储备减少可致低血糖，门脉高压可引发腹水。', '急性早期治疗可恢复，终末期预后差。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_013', '炎症性肠病', 'IBD', 'Inflammatory bowel disease (IBD)', '["消化系统"]', '["犬", "猫"]', '消化系统', '免疫介导性', '犬猫均可发病，犬以中年到老年多见，德国牧羊犬、纯种犬有遗传易感性。猫无明确品种偏好，但中年猫发病率较高。无显著性别差异。部分病例与食物过敏原暴露相关，可能随饮食变化而波动。诊断需排除感染性、肿瘤性等继发原因。', '特发性慢性胃肠道炎症性疾病，特征为持续性GI症状和组织学炎症。', '["食物过敏/不耐受", "肠道菌群失调", "免疫调节异常"]', '肠黏膜免疫失调导致慢性炎症浸润，黏膜屏障损伤导致吸收不良。', 'IBD的核心发病机制是肠黏膜免疫系统对肠道菌群和食物抗原的异常免疫反应。T淋巴细胞、嗜酸性粒细胞、浆细胞等炎症细胞浸润肠壁各层，释放促炎细胞因子（如TNF-α、IL-1、IL-6），导致黏膜屏障完整性破坏。紧密连接蛋白表达下调增加肠通透性（肠漏），进一步加剧抗原暴露和免疫激活，形成恶性循环。慢性炎症导致绒毛萎缩、隐窝增生，引起吸收不良和蛋白丢失性肠病。', '需长期管理，部分可药物控制。', 'advanced', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_014', '扩张型心肌病', 'DCM', 'Dilated cardiomyopathy (DCM)', '["心血管系统"]', '["犬"]', '心血管系统', '退行性', '主要发生于大型和巨型犬种，杜宾犬、大丹犬、爱尔兰猎狼犬、拳师犬等品种具有显著遗传倾向。犬多发于4-8岁，雄性发病率略高于雌性。猫罕见，多与牛磺酸缺乏相关。无明确季节性。', '心室腔扩大伴收缩功能降低，是大型犬最常见的获得性心脏病。杜宾、大丹高发。', '["遗传(杜宾、大丹)", "营养缺乏(牛磺酸)", "特发性"]', '心肌收缩力下降导致心输出量降低，代偿性心室扩张进一步加重瓣膜反流。', 'DCM的核心病理生理是心肌细胞变性、坏死和纤维化导致收缩功能进行性下降。心肌肌节蛋白基因突变或获得性损伤使心肌收缩力减弱，心输出量降低。机体通过Frank-Starling机制代偿性扩张心室腔以维持每搏量，但心室扩张导致二尖瓣环扩大、瓣膜反流，进一步加重容量负荷。神经体液系统（RAAS、交感神经）持续激活导致水钠潴留和前后负荷增加，最终发展为充血性心力衰竭。', '预后差，确诊后中位生存期3-6个月。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_015', '猫肥厚型心肌病', 'HCM', 'Hypertrophic cardiomyopathy (HCM)', '["心血管系统"]', '["猫"]', '心血管系统', '先天性/遗传性', '是猫最常见的心脏病，中老年猫高发（平均发病年龄约10岁）。缅因猫和布偶猫存在明确的常染色体显性遗传模式（MYBPC3基因突变），美国短毛猫、波斯猫也有较高发病率。无显著性别差异，部分研究提示雄性略多。无季节性。', '左心室壁和/或室间隔向心性肥厚，是猫最常见的心脏病。缅因猫、布偶猫有遗传倾向。', '["遗传(肌节蛋白基因突变)", "继发于甲亢", "继发于高血压"]', '心肌肥厚导致舒张功能障碍，左房压升高引发肺静脉充血和肺水肿。', 'HCM以左心室壁和/或室间隔向心性肥厚为特征，肌节蛋白基因突变导致心肌细胞排列紊乱和间质纤维化。肥厚的心肌导致心室腔缩小、舒张期顺应性降低，左室充盈受阻，左房压升高，进而引发肺静脉充血和肺水肿。同时舒张功能障碍导致心房扩大，血流淤滞易形成血栓。部分病例存在左室流出道动力性梗阻（SAM现象），进一步降低心输出量。', '取决于严重程度，合并动脉血栓预后差。', 'advanced', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_016', '心包积液', 'Pericardial Effusion', 'Pericardial effusion / Cardiac tamponade', '["心血管系统"]', '["犬", "猫"]', '心血管系统', '肿瘤性', '犬发病率高于猫，金毛寻回犬、德国牧羊犬因血管肉瘤高发而风险显著增加。中老年犬多发，无明确性别差异。猫少见，病因多为充血性心力衰竭或感染。恶性病因（血管肉瘤、心包囊腺癌）预后极差，良性病因（特发性、感染性）经治疗预后相对较好。', '心包腔内液体异常积聚，可导致心脏压塞。犬最常见病因是血管肉瘤。', '["血管肉瘤(金毛、德牧)", "心包囊腺癌", "感染性心包炎", "特发性"]', '心包内液体积聚导致心包压升高，心室舒张受限，心输出量急剧下降。', '心包腔内液体异常积聚导致心包内压升高，当超过右室舒张压时即发生心脏压塞。心室舒张受限导致静脉回流减少、每搏量和心输出量急剧下降。代偿性心动过速和全身血管收缩短期内维持血压，但随积液量增加最终失代偿。同时心室间相互依赖增强，呼吸周期中左右心室充盈量交替变化，表现为奇脉。冠脉灌注压降低可致心肌缺血。', '恶性病因预后极差。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_017', '糖尿病', 'Diabetes Mellitus', 'Diabetes mellitus', '["内分泌系统"]', '["犬", "猫"]', '内分泌系统', '代谢性', '犬多为I型糖尿病（自身免疫性beta细胞破坏），母犬发病率约为公犬2倍，中老年犬多发，萨摩耶、澳大利亚梗、迷你雪纳瑞等品种有遗传易感性。猫多为II型糖尿病（胰岛素抵抗），肥胖猫、去势公猫风险更高。犬无季节性，猫诊断率在冬季可能略高。', '胰岛素分泌不足或胰岛素抵抗导致的高血糖综合征。犬多为I型，猫多为II型。', '["自身免疫性beta细胞破坏(犬)", "胰岛素抵抗/肥胖(猫)", "胰腺炎后继发", "药物(糖皮质激素)"]', '胰岛素不足导致葡萄糖利用障碍而高血糖，脂肪分解增加导致酮体生成和酮症酸中毒。', '胰岛素绝对或相对不足导致组织细胞葡萄糖利用障碍，血糖持续升高超过肾糖阈（犬约11 mmol/L，猫约14 mmol/L）出现糖尿和渗透性利尿。同时脂肪分解加速，游离脂肪酸在肝脏经β氧化生成大量酮体，超过外周组织利用能力时发生酮症酸中毒。蛋白质分解增加导致负氮平衡和体重下降。长期高血糖导致糖基化终产物蓄积，引发微血管病变（视网膜病变、肾病、神经病变）。', '需终身胰岛素治疗(犬)，猫部分可缓解。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_018', '库欣综合征', 'Hyperadrenocorticism', 'Hyperadrenocorticism / Cushing''s syndrome', '["内分泌系统"]', '["犬", "猫"]', '内分泌系统', '肿瘤性', '犬多发，垂体依赖性占85%，肾上腺肿瘤占15%。犬发病年龄多在中老年（7-12岁），贵宾犬、腊肠犬、小型梗犬等品种易感。猫罕见，多为肾上腺肿瘤。母犬发病率略高于公犬。医源性库欣与长期使用糖皮质激素相关，无品种偏好。', '肾上腺皮质分泌过多皮质醇导致的临床综合征。犬多为垂体依赖性(85%)。', '["垂体ACTH瘤(85%犬)", "肾上腺肿瘤(15%)", "医源性(长期使用糖皮质激素)"]', '皮质醇过量导致蛋白质分解增加(皮肤变薄、肌肉萎缩)、肝糖异生增加(高血糖)、免疫抑制。', '皮质醇持续过量分泌导致多系统病理生理改变：促进肝糖异生并抑制外周葡萄糖利用，导致类固醇性糖尿病；促进蛋白质分解代谢，引起皮肤变薄、肌肉萎缩、腹部膨隆（悬腹）；抑制免疫功能，增加感染风险；抑制成纤维细胞活性，伤口愈合延迟；促进肾小管钠重吸收和钾排泄，导致低钾血症；增加胃酸分泌和降低胃黏膜保护，增加消化性溃疡风险。垂体ACTH瘤导致双侧肾上腺弥漫性增生。', '垂体依赖性经药物控制中位生存期2-3年。', 'advanced', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_019', '猫甲状腺功能亢进', 'Feline Hyperthyroidism', 'Feline hyperthyroidism / Thyrotoxicosis', '["内分泌系统"]', '["猫"]', '内分泌系统', '肿瘤性', '是老年猫最常见的内分泌疾病，多发于10岁以上猫，13岁以上猫发病率可达10%。无明确品种偏好，但部分研究提示暹罗猫和喜马拉雅猫发病率略低。无性别差异。环境因素（罐头食品中双酚A和邻苯二甲酸酯暴露、猫砂中的多溴联苯醚）可能增加发病风险。', '甲状腺激素过度分泌，是老年猫最常见的内分泌疾病。多为甲状腺腺瘤样增生。', '["甲状腺腺瘤样增生(95%)", "甲状腺腺癌(<5%)"]', 'T3和T4升高导致基础代谢率增加，蛋白质分解增加(体重下降但食欲增加)，心率增加可引发HCM。', '甲状腺腺瘤样增生或腺癌导致T3和T4自主性过度分泌，不受下丘脑-垂体-甲状腺轴负反馈调节。甲状腺激素增加基础代谢率，促进蛋白质、脂肪和糖原分解，导致体重下降但食欲亢进。心血管系统对儿茶酚胺敏感性增加，导致心动过速、心肌收缩力增强，长期可引发继发性肥厚型心肌病（甲状腺性心脏病）。中枢神经系统兴奋性增加导致多动、易激惹。肝酶升高反映肝细胞代谢负荷增加。', '药物或放射性碘治疗效果良好。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_020', '甲状腺功能减退', 'Hypothyroidism', 'Hypothyroidism', '["内分泌系统"]', '["犬"]', '内分泌系统', '免疫介导性', '是犬最常见的内分泌疾病，多发于中老年犬（4-10岁）。金毛寻回犬、杜宾犬、爱尔兰雪达犬、大麦町犬、可卡犬等品种有遗传易感性。已去势犬风险略高。无明确季节性。猫罕见，多为先天性或医源性。', '甲状腺激素分泌不足，是犬最常见的内分泌疾病。多为自身免疫性甲状腺炎。', '["自身免疫性淋巴性甲状腺炎", "特发性甲状腺萎缩", "先天性(罕见)"]', 'T3和T4下降导致基础代谢率降低，体重增加、怕冷、嗜睡。', '甲状腺激素（T3、T4）分泌不足导致全身基础代谢率降低。自身免疫性淋巴性甲状腺炎是主要病因，淋巴细胞浸润和抗甲状腺抗体导致甲状腺滤泡进行性破坏和纤维化。代谢减慢导致体重增加（尽管食欲降低）、怕冷、嗜睡。皮肤因黏多糖沉积呈现黏液性水肿（tragic face）。高胆固醇血症因LDL受体表达下调导致脂质清除减少。心肌收缩力减弱、心率减慢导致心输出量降低。神经髓鞘代谢减慢可引发外周神经病变。', '需终身甲状腺素替代治疗，预后极好。', 'basic', 1);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_021', '乙二醇中毒', 'Ethylene Glycol', 'Ethylene Glycol Toxicosis', '["中毒与急救"]', '["犬", "猫"]', '泌尿系统', '中毒性', '多发于冬季防冻剂使用季节，犬比猫更常见。犬因甜味而主动舔食，猫因接触被污染的物体而中毒。无品种和性别倾向，户外散养犬风险最高。', '防冻剂中毒，代谢为草酸钙结晶沉积于肾小管导致AKI。猫致死剂量仅1.5ml/kg。', '["摄入防冻剂(汽车冷却液)", "园林产品", "某些油漆溶剂"]', '乙二醇代谢为草酸，与钙结合形成草酸钙结晶沉积于肾小管导致机械性损伤和缺血。', '乙二醇本身毒性较低，但经肝脏醇脱氢酶代谢为一系列毒性代谢产物：乙醇醛、乙醇酸、乙醛酸，最终生成草酸。草酸与血清钙结合形成草酸钙结晶，沉积于肾小管腔内造成机械性阻塞和上皮细胞坏死。同时代谢产物直接损伤肾小管细胞，导致急性肾小管坏死。中枢神经系统在早期受乙二醇原形影响出现醉酒样症状，后期草酸钙结晶也可沉积于脑组织。', '犬12-24h内治疗可能存活，猫预后极差。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_022', '巧克力中毒', 'Chocolate Toxicity', 'Methylxanthine Toxicosis (Chocolate Toxicity)', '["中毒与急救"]', '["犬"]', '心血管系统', '中毒性', '犬最常见，尤其是贪吃的幼犬和小型犬。黑巧克力和烘焙巧克力毒性最高。无性别倾向，全年可发，节假日期间（万圣节、圣诞节、复活节）发病率显著升高。', '可可碱和咖啡因中毒，刺激中枢神经系统和心血管系统。黑巧毒性最高。', '["摄入巧克力", "可可制品"]', '可可碱抑制腺苷受体导致中枢兴奋，磷酸二酯酶抑制导致cAMP升高引发心律失常。', '巧克力中的主要毒性成分为可可碱和咖啡因，属于甲基黄嘌呤类化合物。其机制包括：(1) 竞争性抑制腺苷受体，导致中枢神经系统兴奋和惊厥阈值降低；(2) 抑制磷酸二酯酶，使细胞内cAMP浓度升高，增强心肌收缩力和心率；(3) 促进肌浆网释放钙离子，增强心肌兴奋性。这些综合作用导致心律失常（室性早搏、室性心动过速）、骨骼肌兴奋和胃肠痉挛。犬代谢可可碱的半衰期长达17.5小时，因此中毒持续时间较长。', '轻度预后好，严重心律失常可致死。', 'basic', 1);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_023', '百合中毒', 'Lily Toxicity', 'Lilium spp. Nephrotoxicity', '["中毒与急救"]', '["猫"]', '泌尿系统', '中毒性', '仅发生于猫，犬不敏感。所有百合科植物（复活节百合、虎百合、亚洲百合等）均具毒性，包括叶片、花瓣、花粉和浸泡花瓶的水。无品种、年龄和性别倾向，室内猫因接触盆栽或切花而中毒。全年可发。', '百合属植物对猫有剧毒，任何部位(包括花粉和水)均可导致AKI。', '["摄入百合属植物", "接触花粉", "饮用百合花瓶水"]', '肾小管上皮细胞坏死导致AKI，机制尚未完全明确。', '百合中毒的确切肾毒性成分尚未完全分离鉴定，但已知其导致急性肾小管坏死。病理过程为：摄入后肾小管上皮细胞发生变性坏死，细胞脱落阻塞肾小管，肾小球滤过率急剧下降。组织学上可见肾小管上皮细胞空泡变性、坏死和钙化。同时伴有肾间质水肿和炎症反应。少尿期通常在摄入后24-72小时出现，如不及时干预可进展为无尿型肾衰竭。猫对此毒素的敏感性远高于其他动物，具体机制可能与猫缺乏某些肝脏代谢酶有关。', '摄入后8h内积极治疗可挽救，延误则致死率极高。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_024', '布洛芬中毒', 'Ibuprofen Toxicity', 'Ibuprofen Toxicosis', '["中毒与急救"]', '["犬", "猫"]', '消化系统', '中毒性', '犬和猫均可发生，但猫因缺乏葡萄糖醛酸转移酶而对NSAIDs极为敏感。最常见原因为主人自行给宠物喂药。无品种和性别倾向，全年可发。幼龄和老年动物风险更高。', 'NSAIDs中毒，猫极为敏感。', '["主人自行喂药", "误食药物", "过量使用"]', 'COX-1抑制导致胃黏膜PG合成减少引发胃溃疡，肾血管收缩导致肾血流减少引发AKI。', '布洛芬为非选择性环氧化酶（COX）抑制剂，同时抑制COX-1和COX-2。COX-1抑制导致胃黏膜前列腺素E2（PGE2）合成减少，进而引起胃黏膜血流减少、黏液分泌降低和碳酸氢盐分泌减少，破坏胃黏膜屏障，导致胃溃疡和穿孔。在肾脏，COX抑制导致肾血管收缩、肾血流量减少和肾小球滤过率下降，尤其在低血容量状态下更易发生急性肾损伤。此外，布洛芬还可引起血小板功能抑制，加重出血倾向。猫的毒性剂量远低于犬（猫>25mg/kg即可中毒）。', '剂量依赖，猫>50mg/kg可致死。', 'basic', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_025', '犬细小病毒病', 'Parvovirus', 'Canine Parvovirosis', '["传染病"]', '["犬"]', '消化系统', '病毒性', '主要影响6周至6月龄未免疫幼犬，罗威纳、杜宾、比特犬等品种易感性更高。CPV-2各亚型（2a/2b/2c）全球分布。环境卫生差、多犬密集场所（犬舍、收容所）高发。全年可发，夏秋季略多。', '高度传染性病毒性肠炎，主要影响未免疫幼犬。特征为严重出血性肠炎和白细胞减少。', '["CPV-2(2a/2b/2c型)", "未免疫/免疫失败"]', '病毒感染肠隐窝上皮导致细胞坏死和肠绒毛萎缩，骨髓抑制导致白细胞急剧下降。', 'CPV-2通过粪-口途径感染，先在口咽部和肠系膜淋巴结中复制，形成病毒血症。病毒靶向分裂活跃的细胞，尤其肠隐窝上皮细胞。感染后肠隐窝上皮细胞大量坏死脱落，导致肠绒毛萎缩变短，吸收表面积急剧减少，引起严重出血性肠炎和吸收不良。同时病毒侵犯骨髓前体细胞，导致中性粒细胞和淋巴细胞急剧减少（泛白细胞减少），严重削弱免疫防御。肠道屏障破坏后细菌移位可引发败血症和内毒素血症。', '未治疗死亡率91%，积极治疗存活率80-90%。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_026', '犬瘟热', 'Canine Distemper', 'Morbilli (Canine Distemper)', '["传染病"]', '["犬"]', '多系统', '病毒性', '主要影响未免疫的3-6月龄幼犬，但任何年龄的未免疫犬均可感染。雪貂、浣熊等野生动物可为本病的储存宿主。多犬密集环境传播迅速。冬季发病率较高，可能与病毒在低温下存活时间更长有关。', '犬瘟热病毒引起的多系统感染，可影响呼吸、消化和神经系统。', '["CDV", "未免疫", "接触感染犬分泌物"]', '病毒先在淋巴系统复制后形成病毒血症，多系统感染，神经损伤可为不可逆。', '犬瘟热病毒（CDV）属于副黏病毒科麻疹病毒属，通过呼吸道分泌物传播。感染后病毒先在呼吸道淋巴组织复制，经淋巴和血液播散至全身上皮组织和中枢神经系统。病毒对淋巴组织（胸腺、脾脏、淋巴结）的破坏导致严重的免疫抑制。呼吸道感染引起双侧浆液性至黏液脓性鼻分泌物和肺炎。消化道感染导致呕吐和腹泻。神经系统感染可表现为脑炎、脊髓炎、小脑变性，病毒在神经细胞内包涵体形成导致脱髓鞘病变，神经损伤常为不可逆性。', '神经症状出现后预后差，存活犬可能有永久性后遗症。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_027', '猫泛白细胞减少症', 'Feline Panleukopenia', 'Feline Panleukopenia', '["传染病"]', '["猫"]', '消化系统', '病毒性', '主要影响未免疫的幼猫（3-5月龄最易感），但任何年龄猫均可发病。FPV极其稳定，在环境中可存活一年以上。多猫家庭、猫舍和流浪猫群体中传播迅速。无品种和性别倾向，春季（繁殖季节后幼猫增多）发病率升高。', '猫细小病毒引起的高度传染性病毒病，特征为泛白细胞减少和出血性肠炎。', '["FPV", "未免疫"]', '病毒感染分裂活跃的细胞(肠隐窝、骨髓)导致肠炎和泛白细胞减少。', 'FPV为单链DNA病毒，靶向分裂活跃的细胞。病毒经口鼻感染后在口咽部淋巴组织复制，形成病毒血症后播散至肠隐窝上皮和骨髓。肠隐窝上皮细胞坏死导致严重出血性肠炎和肠绒毛萎缩，临床表现剧烈呕吐和血便。骨髓感染导致泛白细胞减少（白细胞可降至<1000/μL），其中中性粒细胞减少最为显著，造成严重免疫抑制。妊娠母猫感染可导致胎儿小脑发育不全，出生后表现为小脑性共济失调。', '未治疗死亡率>90%，积极治疗存活率约50%。', 'intermediate', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_028', '猫传染性腹膜炎', 'FIP', 'Feline Infectious Peritonitis', '["传染病"]', '["猫"]', '多系统', '病毒性（免疫介导性）', '多发于2岁以下年轻猫（6月-2岁高峰），纯种猫（波斯、伯曼、布偶等）遗传易感性更高。多猫环境（猫舍、收容所）中FCoV流行率高，但仅少数（5-10%）感染FCoV的猫发展为FIP。应激是重要的诱发因素。', '猫冠状病毒突变引起的免疫介导性血管炎，分为湿性和干性。预后极差。', '["FCoV突变", "多猫环境", "应激", "遗传易感性"]', '突变病毒在巨噬细胞中复制，免疫复合物沉积于血管壁导致血管炎。', 'FIP的发病机制核心是猫肠道冠状病毒（FCoV）在个体内发生突变，获得在单核-巨噬细胞系中有效复制的能力。突变病毒在巨噬细胞中持续复制，激发III型（免疫复合物介导）和IV型（细胞介导）超敏反应。免疫复合物沉积于小血管壁激活补体系统，导致脓性肉芽肿性血管炎。湿性FIP以富含蛋白的渗出液积聚于体腔（腹腔、胸腔）为特征，系血管通透性增加所致。干性FIP以多器官（肾、肝、CNS、眼）脓性肉芽肿为特征。两种形式可同时存在。', '传统观点认为不治之症。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_029', '胃扩张-扭转', 'GDV', 'Gastric Dilatation-Volvulus', '["外科", "急诊"]', '["犬"]', '消化系统', '外伤性', '大型和巨型深胸犬种高发，大丹犬、圣伯纳、威玛犬、德国牧羊犬、标准贵宾犬等风险最高。中老年犬（>7岁）发病率显著升高。公犬略多于母犬。饭后剧烈运动、大量进食或饮水为常见诱因。', '胃内气体/液体积聚并发生轴向扭转，是大型深胸犬的致命急症。', '["大型/巨型犬(大丹、德牧)", "老年", "饭后剧烈运动"]', '胃扭转导致贲门和幽门闭塞，胃内压升高导致静脉回流受阻和胃壁缺血坏死。', 'GDV的病理生理核心是胃沿长轴发生扭转（通常顺时针旋转180-360度），导致贲门和幽门双重梗阻。胃内发酵气体和分泌物无法排出而积聚，胃内压急剧升高。胃扩张首先压迫后腔静脉，减少静脉回流导致前负荷下降和心输出量降低。胃壁静脉回流受阻导致胃壁水肿、缺血，最终胃壁坏死穿孔。门静脉受压导致内脏淤血和休克。胃左动脉和胃短动脉受压可导致脾脏缺血和梗死。低血压和缺血再灌注损伤释放大量炎症介质，引发全身炎症反应综合征（SIRS）和多器官功能障碍。', '术前死亡率15-30%，胃壁坏死需切除则死亡率>50%。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_030', '子宫蓄脓', 'Pyometra', 'Pyometra', '["外科", "生殖系统"]', '["犬", "猫"]', '生殖系统', '细菌性', '未绝育的中老年母犬最常见，平均发病年龄7-9岁。猫较少见但也可发生。发情后4-8周（黄体期）为高发时段。部分品种（金毛、迷你雪纳瑞、英国斗牛犬等）发病率较高。与孕激素使用史相关。', '子宫内脓液积聚，是未绝育母犬的常见急症。多在发情后4-8周发生。', '["黄体期孕激素作用", "继发细菌感染(大肠杆菌)", "未绝育中老年母犬"]', '孕激素导致子宫内膜增生、子宫颈关闭，细菌在封闭子宫内繁殖导致脓液蓄积和内毒素吸收。', '子宫蓄脓的发生需要两个关键条件：子宫内膜囊性增生（CEH）和继发细菌感染。发情周期中，孕激素持续刺激导致子宫内膜腺体增生、分泌增加，同时子宫肌层收缩力减弱和子宫颈关闭。CEH创造的封闭、富含分泌物的环境为细菌（主要是大肠杆菌）提供了理想的繁殖场所。细菌内毒素持续吸收导致全身中毒症状。严重时子宫壁因过度扩张而缺血坏死，可发生子宫破裂导致腹膜炎和败血症。内毒素还可引发肾小球肾炎（免疫复合物沉积）。', '手术切除预后极好，延误可致子宫破裂和败血症死亡。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_031', '癫痫', 'Epilepsy', 'Epilepsia', '["神经系统"]', '["犬", "猫"]', '神经系统', '特发性/遗传性', '犬特发性癫痫发病率约0.5-5%，多见于6月龄至5岁犬。品种易感性强：金毛寻回犬、拉布拉多、比格犬、德国牧羊犬等有遗传倾向。猫多为继发性癫痫，无明确品种和性别倾向。无季节性差异。', '大脑神经元异常过度放电导致的反复发作性神经功能障碍。犬多为特发性癫痫，猫多为继发性。', '["特发性/遗传性(犬)", "结构性病变(肿瘤、脑炎)", "代谢性(低血糖、肝性脑病)", "中毒"]', '大脑皮层神经元同步异常放电，GABA能抑制功能下降或谷氨酸能兴奋性增强导致发作阈值降低。', '癫痫发作的本质是大脑皮层神经元异常同步化过度放电。在特发性癫痫中，GABA能抑制性神经递质功能下降或谷氨酸能兴奋性递质功能增强，导致神经元膜电位不稳定，发作阈值降低。离子通道（钠、钙、钾通道）功能异常也是重要机制。反复发作可导致海马神经元坏死和胶质增生（兴奋性毒性），形成恶性循环。', '特发性癫痫经药物控制预后良好，但需终身用药。结构性病因预后取决于原发病。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_032', '免疫介导性多关节炎', 'IMPA', 'Arthritidis immunomediata multiplex', '["免疫系统"]', '["犬"]', '免疫系统', '免疫介导性', '好发于2-7岁成年犬，母犬略多于公犬。品种易感性：贵宾犬、史宾格犬、德国牧羊犬、喜乐蒂牧羊犬高发。猫罕见。无季节性，但部分病例在感染或疫苗接种后诱发。约占犬关节疾病的10-15%。', '免疫系统攻击自身关节滑膜导致的对称性多关节炎症。是犬最常见的免疫介导性疾病之一。', '["特发性(最常见)", "药物反应", "肿瘤相关", "感染后免疫复合物沉积"]', '免疫复合物沉积于滑膜血管壁激活补体，中性粒细胞浸润释放蛋白酶和炎症介质导致滑膜增生和关节软骨破坏。', '核心机制为III型超敏反应：循环免疫复合物沉积于滑膜毛细血管壁，激活补体经典途径（C1q结合IgG/IgM），产生C3a、C5a等过敏毒素，趋化中性粒细胞浸润。中性粒细胞释放溶酶体酶（胶原酶、弹性蛋白酶）和炎症介质（前列腺素、白三烯），导致滑膜充血水肿、滑膜细胞增生。持续炎症激活破骨细胞，释放基质金属蛋白酶（MMP），破坏关节软骨和软骨下骨。', '早期积极免疫抑制治疗预后良好，但需长期维持。感染性关节炎必须排除。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_033', '免疫介导性溶血性贫血', 'IMHA', 'Anaemia haemolytica immunomediata', '["免疫系统", "血液系统"]', '["犬", "猫"]', '免疫系统', '免疫介导性', '犬发病率远高于猫，占犬溶血性贫血病例的60-75%。好发于中年犬（3-7岁），母犬发病率是公犬的2-3倍。品种易感性：可卡犬、英国史宾格犬、贵宾犬、老式英国牧羊犬高发。猫多继发于FeLV感染或支原体感染。春季和夏季发病率略高（可能与免疫刺激事件增多有关）。', '免疫系统攻击自身红细胞导致的急性溶血性贫血。犬发病率高，猫多为继发性。致死率高，是内科急症。', '["特发性(犬最常见)", "继发于肿瘤/感染/药物", "猫继发于FeLV/支原体"]', 'IgG或IgM抗体结合红细胞表面抗原，激活补体导致血管内溶血，或巨噬细胞吞噬导致血管外溶血。', 'IMHA的核心病理机制为II型超敏反应。IgG或IgM类自身抗体结合红细胞表面抗原（I型或II型抗原），通过两条途径导致溶血：1）血管外溶血：抗体致敏的红细胞被脾脏和肝脏巨噬细胞通过Fc受体识别并吞噬破坏，形成球形红细胞；2）血管内溶血：IgM抗体激活补体级联反应至膜攻击复合物（MAC），直接在血管内溶解红细胞。血红蛋白释放导致血红蛋白尿和含铁血黄素沉积。', '犬死亡率30-50%，合并DIC预后极差。猫继发性IMHA预后取决于原发病。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_034', '淋巴瘤', 'Lymphoma', 'Lymphoma / Lymphosarcoma', '["肿瘤科"]', '["犬", "猫"]', '免疫系统', '肿瘤性', '是犬猫最常见的造血系统肿瘤。犬发病率约13-24/10万，多中心型最常见（80%以上），高发品种：金毛寻回犬、拳师犬、斗牛犬、圣伯纳犬。猫发病率约200/10万（FeLV流行地区），消化道型最常见。犬多见于6-9岁中年到老年犬，猫多见于9-13岁（FeLV相关）或老年猫（FeLV阴性）。犬无性别倾向，猫公猫略多。', '淋巴细胞的恶性肿瘤，是犬猫最常见的肿瘤类型。犬多为多中心型，猫多为消化道型。', '["遗传易感性(犬)", "FeLV/FIV(猫)", "环境因素(除草剂暴露-犬)", "慢性炎症"]', '淋巴细胞克隆性增殖，侵犯淋巴结、肝脾、骨髓等器官。肿瘤细胞抑制正常造血和免疫功能。', '淋巴瘤起源于淋巴细胞（B细胞或T细胞）的恶性克隆性增殖。B细胞型占犬淋巴瘤的60-80%，T细胞型预后更差。肿瘤细胞通过以下机制致病：1）淋巴结结构破坏导致免疫监视功能丧失；2）肝脾浸润导致器官肿大和功能障碍；3）骨髓浸润导致正常造血抑制（全血细胞减少）；4）肿瘤细胞分泌细胞因子导致副肿瘤综合征（高钙血症、恶病质）。染色体易位（如BCL-2基因重排）和表观遗传异常驱动细胞凋亡逃逸和不受控增殖。', '犬不治疗中位生存期4-6周，化疗后12-14个月。猫低度恶性可达2年。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_035', '前十字韧带撕裂', 'CCL Tear', 'Rupture ligamenti cruciati cranialis', '["外科", "骨科"]', '["犬"]', '运动系统', '退行性', '是犬最常见的骨科疾病之一，年发病率约1.2-2.5%。好发于2-10岁大型犬和巨型犬，高发品种：拉布拉多寻回犬、金毛寻回犬、罗威纳犬、纽芬兰犬。肥胖犬风险增加3-5倍。母犬略多于公犬。约30-40%病例在12-18个月内对侧膝关节也发生撕裂。无明显季节性。', '前十字韧带(ACL)部分或完全断裂，是犬最常见的骨科手术指征。多见于大型犬和肥胖犬。', '["退行性韧带变性(最常见)", "肥胖", "品种易感性(拉布拉多、金毛)", "外伤性(少见)"]', '韧带变性导致机械强度下降，轻微外力即可断裂。关节不稳定导致继发性骨关节炎和半月板损伤。', '犬前十字韧带撕裂绝大多数为退变性而非外伤性。韧带胶原纤维（主要是I型胶原）发生渐进性粘液样变性和纤维化，导致韧带机械强度下降，在正常运动负荷下即可发生部分或完全断裂。断裂后胫骨前移和旋转不稳定，导致：1）内侧半月板后角受压撕裂（约50%病例）；2）关节滑膜增生和关节囊纤维化；3）异常力学刺激激活破骨细胞，关节软骨退变加速，进行性骨关节炎。炎症介质（IL-1、TNF-alpha、PGE2）进一步破坏软骨基质。', '手术修复后预后良好，80-90%恢复良好功能。未手术将进行性骨关节炎。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_036', '心丝虫病', 'Heartworm Disease', 'Dirofilariasis / Heartworm Disease', '["寄生虫", "心血管系统"]', '["犬", "猫"]', '心血管系统', '寄生虫性', '全球分布，主要见于热带和亚热带地区。中国长江流域、华南、东北地区均有报道。犬感染率在未预防地区可达10-40%，猫约为犬的5-20%。蚊虫活跃季节（春末至秋末）为感染高峰期，气温15-30摄氏度时传播风险最高。户外活动犬和未预防用药犬风险最高。所有品种犬均易感，但德国牧羊犬对成虫负荷耐受性较差。', '犬恶丝虫(Dirofilaria immitis)寄生于肺动脉和右心，通过蚊虫传播。可导致肺动脉高压和右心衰。', '["蚊虫叮咬传播", "未预防用药", "温暖潮湿地区高发"]', '成虫寄生于肺动脉，机械损伤血管内皮引发肺动脉高压。死亡虫体栓塞肺血管可致急性呼吸衰竭。', '犬恶丝虫成虫（体长15-30cm）寄生于肺动脉主干和右心室，雌虫产出微丝蚴进入血液循环。病理机制包括：1）机械性损伤：成虫刺激肺动脉内皮，引发血管内皮增生和纤维化；2）免疫介导性血管炎：虫体抗原和Wolbachia内共生菌激活免疫反应，导致肺动脉壁炎症；3）肺动脉高压：血管腔狭窄和血管壁弹性下降导致肺血管阻力增加，右心室代偿性肥厚最终失代偿；4）死亡虫体栓塞远端肺血管，引发急性肺栓塞和肉芽肿性炎症。重度感染（>50条成虫）可导致腔静脉综合征。', '犬治疗后预后取决于病变严重程度。猫无特效治疗，以支持治疗为主。预防远优于治疗。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_037', '脓皮症', 'Pyoderma', 'Pyoderma', '["皮肤科"]', '["犬"]', '皮肤系统', '细菌性', '是犬最常见的皮肤病，占所有皮肤病例的15-30%。任何品种犬均可发生，但短毛犬和皮肤褶皱品种（巴哥犬、英国斗牛犬、沙皮犬）高发。继发性脓皮症中，特应性皮炎是最常见原发病（占60%以上）。温暖潮湿季节发病率升高。免疫抑制犬（库欣综合征、甲减）易反复发作。猫罕见，多与免疫抑制或肿瘤相关。', '细菌性皮肤感染，是犬最常见的皮肤病。多为浅表性，常继发于过敏、寄生虫或内分泌疾病。', '["葡萄球菌(最常见)", "继发于特应性皮炎/食物过敏", "内分泌疾病(甲减/库欣)", "皮肤褶皱"]', '皮肤屏障破坏后细菌定植繁殖，释放毒素和酶导致炎症反应。深层感染可形成脓肿和蜂窝织炎。', '脓皮症的核心发病环节为皮肤屏障功能破坏后继发细菌感染。犬皮肤角质层薄（仅3-5层细胞），屏障脆弱。当过敏、寄生虫或内分泌疾病导致皮肤炎症和搔抓损伤后，表皮葡萄球菌（S. pseudintermedius为主）通过粘附素（如蛋白A、纤连蛋白结合蛋白）定植于暴露的真皮层，分泌溶血素、白细胞毒素和蛋白酶破坏组织。浅表型局限于毛囊和表皮深层型侵入真皮和皮下组织，形成脓肿和蜂窝织炎。细菌生物膜形成导致抗生素耐药和慢性反复感染。', '浅表性抗生素治疗预后极好。深层感染需4-6周抗生素。必须治疗原发病以防复发。', 'basic', 1);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_038', '白内障', 'Cataract', 'Cataracta', '["眼科"]', '["犬", "猫"]', '感觉系统', '退行性/代谢性', '是犬最常见的致盲性眼病。遗传性白内障多发于1-5岁年轻犬，高发品种：迷你贵宾犬、可卡犬、迷你雪纳瑞、哈士奇。糖尿病性白内障可在数天至数周内迅速发展，约75%的糖尿病犬在16个月内发生白内障。老年性白内障多见于8岁以上犬。猫白内障少见，多与葡萄膜炎或外伤相关。无明显性别和季节性差异。', '晶状体混浊导致视力下降，是犬最常见的眼科疾病之一。糖尿病性白内障是犬最常见的类型，发展迅速。', '["遗传(常见于贵宾、可卡犬)", "糖尿病(犬最常见继发原因)", "老年退行性变", "外伤", "先天性"]', '晶状体纤维变性导致光散射增加，晶状体透明度下降。糖尿病性白内障因高血糖导致山梨醇蓄积，渗透性水肿破坏晶状体纤维。', '白内障的核心病理改变为晶状体纤维蛋白变性和晶状体透明度丧失。机制包括：1）遗传性：晶状体蛋白（晶体蛋白）基因突变导致蛋白构象异常，光散射增加；2）糖尿病性：高血糖激活醛糖还原酶，葡萄糖转化为山梨醇在晶状体内蓄积，渗透压升高导致晶状体纤维水肿、破裂和变性；3）老年性：氧化应激损伤晶状体蛋白，硫醇基团氧化导致蛋白交联聚集；4）钙离子稳态破坏激活钙依赖性蛋白酶，降解晶体蛋白。晶状体纤维坏死释放蛋白进一步引发晶状体源性葡萄膜炎。', '手术(超声乳化摘除)后预后良好，视力恢复率90%以上。需控制原发病(如糖尿病)。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_039', '青光眼', 'Glaucoma', 'Glaucoma', '["眼科"]', '["犬", "猫"]', '感觉系统', '退行性/先天性', '犬原发性闭角型青光眼发病率约0.5%，高发品种：美国可卡犬、巴塞特猎犬、松狮犬、萨摩耶犬、阿拉斯加雪橇犬，有明显遗传倾向。继发性青光眼更常见，多继发于葡萄膜炎（最常见原因）、晶状体脱位和眼内肿瘤。猫青光眼罕见，多为继发性（葡萄膜炎或肿瘤）。犬多见于4-9岁中年犬，猫多见于老年。无明显季节性，但葡萄膜炎诱发的青光眼在感染活跃季节可能增多。', '眼内压升高导致视网膜和视神经不可逆损伤，是致盲性眼病。急性闭角型青光眼为眼科急症。', '["原发性(遗传，可卡犬、巴塞特猎犬高发)", "继发性(晶状体脱位、葡萄膜炎、眼内肿瘤)", "先天性"]', '房水排出受阻导致眼内压升高，视网膜神经节细胞缺血性损伤。犬急性眼压>40mmHg可在48-72小时内永久失明。', '青光眼的根本病理机制为房水排出障碍导致眼内压（IOP）病理性升高。犬原发性闭角型青光眼因虹膜根部前移，小梁网入口狭窄，房水经小梁网-Schlemm管途径排出受阻。继发性机制包括：炎性渗出物阻塞小梁网（葡萄膜炎相关）、晶状体前脱位机械性阻塞瞳孔（瞳孔阻滞）。持续高IOP（>25mmHg）导致：1）视网膜神经节细胞轴浆流中断和缺血性凋亡；2）视神经乳头凹陷加深（视杯扩大）；3）视网膜光感受器不可逆损伤。犬IOP>40mmHg持续48-72小时即可造成永久失明。', '早期治疗可延缓进展，已失明者不可逆。需终身管理，对侧眼有发病风险。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_040', '角膜溃疡', 'Corneal Ulcer', 'Ulcera corneae', '["眼科"]', '["犬", "猫"]', '感觉系统', '外伤性/感染性', '是犬最常见的眼科急症之一。短头种犬（巴哥犬、斗牛犬、北京犬）因眼球突出和角膜暴露而高发。猫角膜溃疡多见于幼猫（猫疱疹病毒相关）和老年猫（肿瘤相关）。外伤性溃疡无品种和年龄偏好。干眼症相关溃疡多见于老年母犬，高发品种：西高地白梗、骑士查理王猎犬、英国斗牛犬。温暖季节因户外活动增加，外伤性溃疡发病率升高。', '角膜上皮缺损，可由外伤、感染、干眼症或眼睑异常引起。深部溃疡和穿孔为眼科急症。', '["外伤(猫抓伤最常见)", "感染(细菌、真菌)", "干眼症(KCS)", "眼睑内翻/倒睫", "暴露性(面神经麻痹)"]', '角膜上皮屏障破坏后基质暴露，胶原酶活化导致基质溶解。深后弹力层膨出可致角膜穿孔。', '角膜溃疡的核心病理过程为角膜上皮缺损后基质层暴露和降解。正常角膜上皮是抵御微生物和机械损伤的第一道屏障。上皮缺损后：1）基质层胶原暴露，基质金属蛋白酶（MMP-2、MMP-9）和胶原酶被激活，消化角膜胶原纤维导致基质溶解；2）细菌（葡萄球菌、假单胞菌）通过粘附素定植于暴露基质，分泌蛋白酶和毒素加速组织破坏；3）角膜基质变薄至后弹力层时，眼内压推动后弹力层向前膨出（后弹力层膨出），随时可能穿孔；4）穿孔后房水漏出，虹膜脱出，可发展为眼内炎和眼球痨。', '浅表溃疡经治疗1-2周内愈合。深部溃疡需手术(角膜移植/结膜瓣)，穿孔预后差。', 'intermediate', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_041', '椎间盘疾病', 'IVDD', 'Intervertebral Disc Disease', '["骨科", "神经系统"]', '["犬"]', '神经系统/运动系统', '退行性', '腊肠犬、比格犬、法国斗牛犬等软骨营养不良品种高发，与遗传性椎间盘退变密切相关。多发于3-7岁，无明显性别倾向。小型犬以颈椎和胸腰段多见，大型犬以腰椎为主。', '椎间盘退变后突出或脱出压迫脊髓，是犬最常见的脊髓疾病。腊肠犬、比格犬等软骨营养不良品种高发。', '["遗传性软骨营养不良(腊肠犬、比格犬)", "年龄相关退行性变", "外伤"]', '椎间盘髓核钙化后突然突出压迫脊髓，导致脊髓水肿、缺血和神经功能缺损。根据压迫程度分为I-V级。', '遗传性软骨营养不良导致椎间盘髓核早期钙化和纤维化，失去弹性缓冲功能。在轻微外力或正常活动下，变性髓核经破裂的纤维环突出或脱出至椎管，直接压迫脊髓并引发脊髓水肿、缺血性损伤。急性压迫导致微血管痉挛和血-脊髓屏障破坏，慢性压迫则引起脱髓鞘和胶质增生。压迫程度决定神经功能缺损的严重性，从疼痛、共济失调到瘫痪不等。', 'I-II级保守治疗预后好；III-V级需手术减压。深痛觉消失超过48h预后极差。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_042', '髋关节发育不良', 'Hip Dysplasia', 'Hip Dysplasia', '["骨科"]', '["犬"]', '运动系统', '先天性/遗传性', '大型犬和巨型犬高发，金毛寻回犬、拉布拉多、德国牧羊犬、圣伯纳等品种易感性最高。部分研究显示母犬发病率略高。快速生长期（4-12月龄）是发病关键窗口，营养过剩和环境因素可加重病情。', '髋关节窝和股骨头匹配不良导致关节不稳定和退行性关节病，是大型犬最常见的骨科疾病。', '["遗传(金毛、拉布拉多、德牧高发)", "快速生长", "营养过剩(高热量饮食)", "运动不当"]', '髋关节松弛导致半脱位，关节软骨磨损，继发骨关节炎。进行性关节破坏导致疼痛和功能障碍。', '髋关节发育过程中，髋臼和股骨头的生长速率不匹配，导致关节松弛和半脱位。关节不稳定引发关节囊纤维化和关节软骨退行性变，继而发展为骨关节炎。进行性关节面破坏导致疼痛、跛行和活动受限。关节松弛程度与遗传因素密切相关，多基因遗传模式已被证实。', '早期干预(幼年骨盆切开术)预后好。成年犬以药物管理和体重控制为主，严重者需股骨头切除或全髋置换。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_043', '肥大细胞瘤', 'Mast Cell Tumor', 'Mast Cell Tumor', '["肿瘤科"]', '["犬", "猫"]', '皮肤系统/免疫系统', '肿瘤性', '犬最常见的皮肤肿瘤，占皮肤肿瘤约20%。斗牛犬、拳师犬、波士顿梗、拉布拉多等品种高发。多发于中老年犬（平均8-10岁），无明显性别倾向。猫以皮肤型和内脏型均可发生，暹罗猫内脏型风险较高。', '肥大细胞来源的肿瘤，是犬最常见的皮肤肿瘤(占20%)，也是猫最常见的皮肤和内脏肿瘤之一。', '["遗传易斗牛犬、拳师犬高发)", "慢性炎症刺激", "c-kit基因突变"]', '肥大细胞脱颗粒释放组胺、肝素等介质，可导致局部红肿、胃溃疡和过敏反应。高分级肿瘤可转移至淋巴结和内脏。', '肥大细胞异常增殖形成肿瘤，c-kit基因突变（特别是外显子11内部串联重复）是犬肥大细胞瘤的重要驱动突变。肿瘤性肥大细胞脱颗粒释放组胺、肝素、蛋白酶等生物活性介质，导致局部红肿、水肿、胃溃疡和凝血异常。高分级肿瘤具有侵袭性生长和早期转移倾向，常转移至区域淋巴结、肝、脾和骨髓。肿瘤分级（Patnaik或Kiupel系统）是预后的关键决定因素。', '犬低分级(I-II)手术切除后中位生存期>2年；高分级(III)预后差。猫皮肤型预后好，内脏型预后差。', 'advanced', 3);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_044', '血管肉瘤', 'Hemangiosarcoma', 'Hemangiosarcoma', '["肿瘤科"]', '["犬"]', '心血管系统', '肿瘤性', '金毛寻回犬、德国牧羊犬、拉布拉多等深胸大型犬种高发，与遗传易感性密切相关。多发于中老年犬（8-13岁），公犬发病率略高于母犬。皮下型与紫外线暴露相关，浅肤色犬风险更高。', '血管内皮细胞的恶性肿瘤，高度侵袭性和转移性。最常见部位为脾脏、右心和皮下。金毛、德牧高发。', '["遗传易感性(金毛寻回犬)", "紫外线暴露(浅肤色犬皮下型)", "慢性异物刺激"]', '肿瘤生长迅速，易自发性破裂导致致命性出血。早期血行转移至肺、肝和脑。', '血管内皮细胞恶性转化形成肿瘤，最常见于脾脏、右心耳和皮下组织。肿瘤组织脆弱易碎，自发性破裂导致致命性腹腔或心包腔出血是其最危险的并发症。肿瘤细胞早期经血行转移至肺、肝、脑和网膜。分子水平上，VEGF通路异常激活促进肿瘤血管生成，p53和PTEN等抑基因失活促进肿瘤进展。', '极差。单纯手术中位生存期1-3月，联合化疗可延长至6-8月。', 'advanced', 5);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_045', '异位性皮炎', 'Canine Atopic Dermatitis', 'Canine Atopic Dermatitis', '["皮肤科"]', '["犬"]', '皮肤系统', '免疫介导性', '犬最常见的过敏性皮肤病，发病率约10-15%。西高地白梗、拉布拉多、法国斗牛犬、金毛寻回犬等品种遗传易感性高。多发于1-3岁青年犬，无明显性别倾向。部分病例具有季节性（花粉过敏），非季节性过敏原（尘螨、霉菌）则全年发病。', '遗传性过敏反应性炎症性皮肤病，是犬最常见的皮肤病。特征为慢性瘙痒，多始于1-3岁。', '["遗传性IgE介导的超敏反应", "环境过敏原(尘螨、花粉、霉菌)", "皮肤屏障缺陷"]', '过敏原经皮肤进入，被朗格汉斯细胞呈递，Th2型免疫反应导致IgE产生和肥大细胞脱颗粒，释放炎症介质引起瘙痒。', '遗传性皮肤屏障缺陷（特别是丝聚蛋白基因突变）使环境过敏原易于穿透表皮。过敏原被朗格汉斯细胞捕获并呈递，激活Th2型免疫应答，产生大量过敏原特异性IgE。IgE与肥大细胞表面FcRI结合，再次接触过敏原时触发肥大细胞脱颗粒，释放组胺、白三烯、前列腺素等炎症介质，引起剧烈瘙痒。慢性炎症导致表皮增生、苔藓化和色素沉着，皮肤屏障功能进一步恶化，形成恶性循环。', '需终身管理，无法根治。奥克拉珠单抗靶向治疗效果好。继发感染需积极控制。', 'intermediate', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_046', '钩端螺旋体病', 'Leptospirosis', 'Leptospirosis', '["传染病"]', '["犬", "猫"]', '泌尿系统/肝胆系统', '细菌性', '主要通过接触受感染动物（特别是鼠类）尿液污染的水源传播。公犬因嗅探行为暴露风险更高。温暖潮湿气候地区多发，雨季和洪水后发病率显著升高。未免疫犬、户外犬和猎犬风险最高。', '人畜共患的螺旋体感染，可导致急性肝肾衰竭。主要通过接触受感染动物尿液污染的水源传播。', '["钩端螺旋体(血清型: icterohaemorrhagiae, canicola, pomona)", "接触污染水源", "野生动物传播"]', '螺旋体经黏膜侵入后血行播散至肝肾，导致肾小管间质性肾炎和肝细胞损伤。', '钩端螺旋体经黏膜或皮肤破损处侵入，进入血行播散至全身各器官，以肾脏和肝脏为主要靶器官。螺旋体在肾小管中繁殖，引发间质性肾炎和肾小管功能障碍，导致蛋白尿和氮质血症。肝脏受累表现为肝细胞损伤和胆汁淤积性黄疸。部分血清型（如icterohaemorrhagiae）可引发血管内皮损伤，导致出血性素质、DIC和肺出血。', '早期抗生素+支持治疗预后良好。严重肝肾衰竭或肺出血型预后差。可传播给人。', 'intermediate', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_047', '脂肪肝(猫)', 'Hepatic Lipidosis', 'Hepatic Lipidosis', '["消化系统"]', '["猫"]', '消化系统', '代谢性', '猫最常见的肝病，肥胖猫和中老年猫高发。任何导致厌食或禁食的疾病（胰腺炎、糖尿病、胆管炎、肿瘤等）均可诱发。无明显品种和性别倾向，但家养短毛猫和波斯猫报道较多。体重快速下降是重要诱因。', '肝细胞内大量甘油三酯蓄积导致肝功能衰竭，是猫最常见的肝病。多由厌食/禁食诱发，肥胖猫高发。', '["厌食/禁食(最常继发于其他疾病)", "肥胖", "糖尿病", "胰腺炎", "甲亢"]', '机体能量需求增加时脂肪大量动员至肝脏，超过肝脏氧化和转运能力导致肝细胞脂肪变性。严重时胆汁排泄障碍导致黄疸。', '厌食或禁食状态下，机体动员外周脂肪组织释放大量游离脂肪酸至肝脏。当脂肪酸输入量超过肝脏的氧化能力和极低密度脂蛋白（VLDL）分泌能力时，甘油三酯在肝细胞内大量蓄积，导致肝细胞脂肪变性和功能障碍。严重脂肪肝影响胆汁排泄，导致肝内胆汁淤积和高胆红素血症。同时，肝脏合成功能下降导致低白蛋白血症和凝血障碍。', '积极营养支持(鼻饲/食道饲管)后预后良好，存活率可达80%。延误治疗可致死。', 'intermediate', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_048', '免疫介导性血小板减少症', 'ITP', 'Immune-Mediated Thrombocytopenia', '["免疫系统", "血液系统"]', '["犬"]', '血液系统/免疫系统', '免疫介导性', '犬最常见的获得性出血性疾病，母犬发病率约为公犬的2倍。可发生于任何品种，但贵宾犬、可卡犬、德国牧羊犬和古代英国牧羊犬等品种易感性较高。多发于中年犬（4-8岁），可继发于感染、肿瘤、药物或疫苗接种。', '免疫系统攻击自身血小板导致血小板减少，是犬最常见的获得性出血性疾病。母犬发病率高于公犬。', '["特发性(最常见)", "继发于感染(埃立克体、利什曼)", "药物诱导", "肿瘤相关", "疫苗诱发"]', 'IgG抗体结合血小板表面糖蛋白，被脾脏巨噬细胞吞噬破坏。血小板<30,000/μL时有自发性出血风险。', '自身IgG抗体靶向血小板表面糖蛋白（主要是GPIIb/IIIa和GPIb/IX），致敏的血小板被脾脏和肝脏巨噬细胞通过Fc受体介导的吞噬作用加速破坏。抗体还可结合巨核细胞，抑制血小板生成。当血小板计数降至30,000/L以下时，自发性出血风险显著增加，表现为皮肤瘀点、鼻出血、血尿和黑便。严重者可发生DIC。', '单纯ITP经免疫抑制治疗后70-80%可缓解。合并严重出血或DIC预后差。复发率20-30%。', 'advanced', 4);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_049', '犬副流感', 'Canine Parainfluenza', 'Canine Parainfluenza', '["传染病"]', '["犬"]', '呼吸系统', '病毒性', '犬副流感病毒（CPIV）是犬窝咳综合征的重要病原之一。群养环境（犬舍、寄养所、收容所）中传播迅速，发病率可达100%。各年龄犬均可感染，幼犬和免疫抑制犬症状更重。无明显品种和性别倾向，冬季发病率略高。', '犬副流感病毒(CPIV)引起的高度传染性呼吸道疾病，是犬窝咳综合征的常见病原之一。', '["犬副流感病毒(CPIV)", "多病原混合感染(博德特氏菌)", "群养环境传播"]', '病毒损伤呼吸道纤毛上皮，破坏黏膜屏障，继发细菌感染加重症状。', 'CPIV经呼吸道飞沫传播，感染气管和支气管纤毛上皮细胞，导致纤毛破坏和上皮细胞坏死脱落。受损的黏膜屏障为细菌（特别是支气管败血博德特氏菌）继发感染创造条件。炎症反应引起气管支气管黏膜充血水肿、黏液分泌增多，导致特征性的干性阵发性咳嗽。单纯病毒感染通常自限，但混合感染可发展为支气管肺炎。', '单纯感染5-10天自愈。继发细菌感染需抗生素治疗。预防以疫苗接种为主。', 'basic', 2);
INSERT INTO diseases (id, name_zh, name_en, name_latin, category, species, body_system, pathogenic_type, epidemiology, overview, etiology, pathophysiology, physiological_basis, prognosis, difficulty, urgency_level) VALUES ('dis_050', '子宫蓄脓(猫)', 'Pyometra (Cat)', 'Pyometra', '["外科", "生殖系统"]', '["猫"]', '生殖系统', '细菌性', '未绝育中老年母猫（通常>5岁）在发情后4-8周高发。与犬相比，猫子宫蓄脓发病率较低，但后果同样严重。任何品种均可发生，暹罗猫和缅甸猫有报道倾向。使用外源性孕激素的猫风险显著增加。', '猫的子宫蓄脓，与犬类似但发病率较低。未绝育中老年母猫在发情后易发。', '["黄体期孕激素作用", "继发细菌感染", "未绝育母猫"]', '与犬相同，孕激素导致子宫内膜增生和子宫颈关闭，细菌在封闭子宫内繁殖。', '发情后黄体期，孕激素持续作用于子宫内膜，导致子宫内膜囊性增生（囊性子宫内膜增生-子宫积液综合征）和子宫颈关闭。增生的子宫内膜分泌液积聚在封闭的子宫腔内，为细菌（主要是大肠杆菌）提供了理想的繁殖环境。细菌感染后形成脓液积聚，子宫扩张变薄。严重时子宫破裂导致腹膜炎和败血症，内毒素吸收可引发感染性休克和多器官功能衰竭。', '卵巢子宫切除术预后极好。延误可致子宫破裂和败血症。建议早期绝育预防。', 'intermediate', 3);
