INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_001', 'dis_002', '肺炎有发热+湿咳，心衰有心脏杂音+奔马律');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_002', 'dis_014', '心衰MMVD有瓣膜杂音，DCM有心室扩张+心律失常');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_003', 'dis_001', '哮喘有可逆性气流受限+嗜酸性粒细胞增多');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_005', 'dis_006', 'AKI起病急+肾脏可增大，CKD病程长+肾脏缩小');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_009', 'dis_010', '胰腺炎有剧烈腹痛+fPLI升高，胃肠炎腹痛轻且无酶升高');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_009', 'dis_011', '胰腺炎渐进性腹痛+酶升高，异物有吞食史+影像可见异物');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_017', 'dis_018', '糖尿病血糖高+尿糖，库欣有皮肤变薄+ALP升高');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_017', 'dis_019', '糖尿病血糖高但T4正常，甲亢T4升高但血糖可正常');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_019', 'dis_006', '甲亢T4升高+多食体重下降，CKD有氮质血症+尿比重低');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_015', 'dis_016', 'HCM有心室肥厚+左房扩大，心包积液有心包液暗区');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_025', 'dis_027', '细小有严重出血性肠炎+白细胞↓↓，猫泛白细胞减少类似但感染猫细小病毒');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_007', 'dis_008', 'UTI有菌尿+脓尿，FLUTD可能无菌尿');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_010', 'dis_013', '胃肠炎急性起病且自限，IBD慢性持续性+组织学炎症');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_012', 'dis_028', '肝衰竭有凝血障碍+低白蛋白，FIP有渗出液+球蛋白升高');
INSERT INTO disease_ddx (disease_id,ddx_id,distinguishing_feature) VALUES ('dis_021', 'dis_005', '乙二醇中毒有草酸钙结晶+阴离子间隙升高，其他AKI无此特征');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_001', '阿莫西林-克拉维酸', 'Amoxicillin-Clavulanate', '抗生素（β-内酰胺类）', '阿莫西林为β-内酰胺类抗生素，通过与细菌青霉素结合蛋白（PBP）结合，抑制肽聚糖交联，干扰细胞壁合成，导致细菌溶菌死亡。克拉维酸为β-内酰胺酶抑制剂，自身抗菌活性弱，但能不可逆地与β-内酰胺酶结合，保护阿莫西林不被水解，从而扩展抗菌谱至产酶金黄色葡萄球菌、大肠埃希菌等。两者联用呈杀菌作用，对需氧革兰阳性菌和部分革兰阴性菌有效。', '口服吸收迅速，生物利用度犬约75%、猫约60%，食物对吸收影响小。广泛分布于组织液和体液中，可穿透胎盘屏障但脑脊液浓度低。阿莫西林主要经肾脏排泄，半衰期约1-1.5小时；克拉维酸半衰期相近，约1小时。两者配比（2:1或4:1）确保同步消除，维持有效血药浓度。肾功能不全时需调整剂量。', '["尿路感染", "皮肤感染", "软组织感染", "牙周感染", "呼吸道感染"]', '["青霉素过敏", "严重肾功能不全（需调整剂量）"]', '["胃肠道反应（呕吐、腹泻）", "过敏反应", "肠道菌群失调"]', '胃肠道反应因药物扰乱肠道正常菌群平衡，导致条件致病菌过度生长。过敏反应由β-内酰胺环作为半抗原与载体蛋白结合引发IgE介导的超敏反应。大剂量静脉注射偶见神经系统兴奋，与GABA受体竞争性抑制有关。', '{"犬": "dose=12.5-25 mg/kg, route=PO, frequency=q12h", "猫": "dose=12.5-25 mg/kg, route=PO, frequency=q12h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_002', '恩诺沙星', 'Enrofloxacin', '抗生素（氟喹诺酮类）', '恩诺沙星为氟喹诺酮类杀菌剂，通过抑制细菌DNA旋转酶（拓扑异构酶II）和拓扑异构酶IV，阻断DNA超螺旋化与解旋过程，导致DNA复制和转录受阻。对革兰阴性菌主要靶向DNA旋转酶，对革兰阳性菌主要靶向拓扑异构酶IV。药物在低浓度下呈抑菌作用，高浓度呈杀菌作用，抗菌谱覆盖革兰阴性菌、部分革兰阳性菌及支原体。', '口服生物利用度犬约65-80%、猫约50-70%，组织分布广泛，能穿透前列腺、肺组织和骨组织。在肝内部分代谢为活性代谢物环丙沙星（约30-40%），主要经肾脏排泄（原型+代谢物），半衰期犬约4-7小时、猫约6-8小时。属浓度依赖性抗菌药，AUC/MIC为关键PK/PD参数，建议每日一次给药以优化杀菌效果。', '["尿路感染", "皮肤感染", "呼吸道感染", "前列腺炎", "革兰阴性菌感染"]', '["幼龄动物（软骨毒性）", "猫高剂量（视网膜毒性）", "癫痫病史"]', '["胃肠道反应", "中枢神经系统兴奋", "幼畜软骨损伤", "猫视网膜病变（高剂量）"]', '幼畜软骨毒性因药物与软骨基质中镁离子螯合，抑制软骨细胞蛋白聚糖合成，导致关节软骨侵蚀。猫视网膜毒性因药物在视网膜色素上皮蓄积，产生活性氧自由基损伤光感受器细胞。中枢神经兴奋与抑制性神经递质GABA受体阻断有关。偶见结晶尿，因药物在酸性尿中溶解度降低。', '{"犬": "dose=5-20 mg/kg, route=PO/IV/SC, frequency=q24h", "猫": "dose=2.5-5 mg/kg, route=PO, frequency=q24h（不超过5mg/kg）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_003', '呋塞米', 'Furosemide', '利尿剂（袢利尿剂）', '呋塞米为高效能袢利尿剂，特异性抑制肾单位髓袢升支粗段管腔膜侧的Na⁺/K⁺/2Cl⁻共转运体（NKCC2），减少钠、氯、钾的重吸收，破坏肾髓质渗透梯度，降低尿液浓缩能力，产生强效利尿排钠效应。同时促进肾脏前列腺素合成，扩张肾血管，增加肾血流量约40%，进一步促进利尿。静脉注射后5分钟起效，利尿同时显著降低心脏前负荷。', '口服生物利用度犬约45-60%、猫约50%，起效时间口服30-60分钟、静脉注射5分钟。血浆蛋白结合率高（>95%），主要分布于细胞外液。约50%经肝脏葡萄糖醛酸化代谢，其余以原型经肾脏排泄，半衰期犬约1-1.5小时、猫约1.5-2小时。利尿效应与尿中药物浓度直接相关，反复给药可产生利尿抵抗（braking phenomenon），需间歇给药或联合用药。', '["充血性心力衰竭", "肺水肿", "胸腔积液", "急性肾损伤（促进利尿）", "高钙血症"]', '["脱水", "无尿", "低钾血症", "磺胺类过敏"]', '["脱水", "低钾血症", "低钠血症", "耳毒性（高剂量IV）", "肾前性氮质血症"]', '电解质紊乱（低钾、低钠、低氯性碱中毒）因髓袢Na⁺/K⁺/2Cl⁻转运抑制后，远端肾单位Na⁺-K⁺交换代偿性增加，同时Cl⁻丢失导致碳酸氢根重吸收增多。脱水与低血容量因过度利尿致有效循环血量减少。耳毒性在大剂量静脉推注时出现，因内淋巴液电解质成分改变损伤耳蜗毛细胞。', '{"犬": "dose=2-4 mg/kg, route=IV/IM/PO, frequency=q8-12h（急性）；1-2 mg/kg q12-24h（维持）", "猫": "dose=1-2 mg/kg, route=IV/IM/PO, frequency=q12-24h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_004', '泼尼松龙', 'Prednisolone', '糖皮质激素', '泼尼松龙为糖皮质激素类药物，经细胞内11β-羟类固醇脱氢酶活化后，与胞质糖皮质激素受体（GR）结合，转位入核，通过抑制NF-κB和AP-1等转录因子，减少促炎细胞因子（IL-1、IL-6、TNF-α）和炎症介质合成。同时抑制磷脂酶A2活性，减少花生四烯酸释放，降低前列腺素和白三烯生成。高剂量时抑制T细胞增殖和抗体产生，发挥免疫抑制作用。', '口服吸收良好，生物利用度犬约50-70%。血浆蛋白结合率约90-95%，主要与皮质激素转运蛋白（CBG）结合。在肝脏经葡萄糖醛酸化代谢，半衰期犬约12-36小时（但药效半衰期更长，约36-72小时）。属时间依赖性抗炎药，推荐隔日给药以减少HPA轴抑制。能穿透胎盘屏障并分泌入乳汁。', '["炎症性肠病", "过敏/特应性皮炎", "免疫介导性疾病", "猫哮喘", "肿瘤化疗辅助", "肾上腺皮质功能减退"]', '["真菌感染", "消化性溃疡", "未控制的糖尿病", "库欣综合征", "妊娠"]', '["多饮多尿多食", "胃肠道溃疡", "肌肉萎缩", "皮肤变薄", "免疫抑制", "医源性库欣"]', '医源性库欣综合征因长期超生理剂量使用导致蛋白质分解代谢增加、脂肪重新分布和糖异生增强。免疫抑制增加感染风险因细胞免疫和体液免疫均受抑制。胃肠道溃疡因前列腺素合成减少导致胃黏膜屏障功能下降。HPA轴抑制因负反馈抑制ACTH分泌，导致肾上腺皮质萎缩。', '{"犬": "dose=0.5-1 mg/kg, route=PO, frequency=q12h（抗炎）；0.1-0.25 mg/kg q48h（替代）", "猫": "dose=1-2 mg/kg, route=PO, frequency=q12h（抗炎，猫需更高剂量）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_005', '胰岛素（甘精胰岛素）', 'Insulin Glargine', '胰岛素（长效）', '甘精胰岛素为长效人胰岛素类似物，B链C端添加两个精氨酸使等电点偏酸（pH 4.0），皮下注射后在生理pH下形成微沉淀库，缓慢释放入血。与胰岛素受体α亚基结合后，激活β亚基酪氨酸激酶活性，启动IRS-PI3K-Akt信号通路，促进GLUT4葡萄糖转运体向细胞膜转位，加速骨骼肌和脂肪组织葡萄糖摄取。同时抑制肝糖原分解和糖异生，促进糖原、脂肪和蛋白质合成。', '皮下注射后在皮下组织形成微沉淀，缓慢溶解吸收，无明显吸收峰值。起效时间约1-2小时，作用持续20-24小时，释放曲线平稳。在肝脏和肾脏经胰岛素酶降解，半衰期约5-10小时（但药效持续时间远超半衰期）。犬猫糖尿病治疗中需个体化调整剂量，根据血糖曲线监测调整。', '["犬糖尿病（I型）", "猫糖尿病（II型，部分可缓解）", "糖尿病酮症酸中毒（急性期后）"]', '["低血糖", "胰岛素瘤"]', '["低血糖（最严重）", "注射部位反应", "体重增加", "Somogyi效应（反跳性高血糖）"]', '低血糖为最常见不良反应，因外源性胰岛素过量导致葡萄糖摄取过度而肝糖输出不足。注射部位反应因局部微沉淀刺激皮下组织产生轻度炎症。胰岛素抗体形成可导致药效波动。Somogyi效应为反跳性高血糖，因低血糖触发反向调节激素大量释放。', '{"犬": "dose=0.25-0.5 U/kg, route=SC, frequency=q12h", "猫": "dose=0.25-0.5 U/kg, route=SC, frequency=q12h（猫对胰岛素敏感，需谨慎调整）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_006', '匹莫苯丹', 'Pimobendan', '正性肌力药（PDE-3抑制剂+钙增敏剂）', '匹莫苯丹具有双重正性肌力机制：①抑制磷酸二酯酶III（PDE-3），减少cAMP降解，增加心肌细胞内cAMP浓度，激活PKA，促进钙离子内流和肌浆网钙释放，增强心肌收缩力；②增加心肌肌钙蛋白C对钙离子的敏感性（钙增敏作用），在相同钙浓度下产生更强的收缩力。同时扩张外周血管，降低心脏前后负荷。双重机制使其在增强收缩力的同时不显著增加心肌耗氧量。', '口服吸收迅速，生物利用度犬约60-65%，食物可促进吸收。在肝脏经CYP450酶系代谢为活性代谢物（去甲基匹莫苯丹），后者亦具PDE-3抑制活性。血浆蛋白结合率>90%，半衰期犬约2-3小时（活性代谢物约4-6小时），但药效持续时间更长。主要经肝脏代谢后由胆汁和肾脏排泄。需每日两次给药维持有效血药浓度。', '["充血性心力衰竭（MMVD/DCM）", "扩张型心肌病", "二尖瓣关闭不全"]', '["肥厚型心肌病（HCM）", "主动脉瓣下狭窄", "心包填塞"]', '["心律失常", "食欲下降", "腹泻", "多动（正性肌力作用）"]', '心律失常因cAMP增加导致心肌自律性增高和触发活动，尤其在已有心律失常风险患畜中需谨慎。胃肠道反应因血管扩张和胃肠道平滑肌松弛。血小板减少罕见报道，机制可能与免疫介导的血小板破坏有关。高剂量可致低血压因外周血管过度扩张。', '{"犬": "dose=0.2-0.3 mg/kg, route=PO, frequency=q12h（餐前1h给药）", "猫": "dose=0.1-0.25 mg/kg, route=PO, frequency=q12h（猫数据有限）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_007', '甲巯咪唑', 'Methimazole', '抗甲状腺药物（硫脲类）', '甲巯咪唑为硫脲类抗甲状腺药物，通过抑制甲状腺过氧化物酶（TPO）活性，阻断碘化物的氧化、酪氨酸碘化以及碘化酪氨酸的偶联反应，从而抑制甲状腺激素（T3和T4）的生物合成。对已合成的甲状腺激素无拮抗作用，故起效需待体内储存激素耗尽（数周）。大剂量时可轻度抑制外周组织T4向T3的转化，并具有一定的免疫调节作用，可降低甲状腺刺激性免疫球蛋白水平。', '口服吸收迅速完全，生物利用度>80%。可浓集于甲状腺组织，甲状腺内浓度高于血浆。在肝脏经CYP450酶系代谢，半衰期犬约2-6小时、猫约2-4小时。因作用靶点在甲状腺内持续存在，药效持续时间远超半衰期，猫可每日一次给药，犬建议每日两次。能穿透胎盘屏障，妊娠期慎用。', '["猫甲状腺功能亢进", "甲亢术前准备"]', '["严重肝功能不全", "严重肾功能不全", "妊娠（猫）"]', '["呕吐/厌食", "面部瘙痒（猫）", "血液学毒性（粒细胞减少）", "血小板减少", "肝毒性"]', '猫面部瘙痒和自残为特异质反应，可能与免疫介导机制或药物直接毒性有关。粒细胞缺乏症因骨髓抑制导致中性粒细胞生成减少，属严重但罕见的不良反应。肝毒性因CYP450代谢产生的活性中间体损伤肝细胞。血小板减少和再生障碍性贫血为免疫介导的骨髓抑制。', '{"猫": "dose=2.5 mg, route=PO/Transdermal, frequency=q12h（猫用透皮耳膏更安全）", "犬": "dose=不适用（犬甲亢极罕见）, route=-, frequency=-"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_008', '左甲状腺素钠', 'Levothyroxine (T4)', '甲状腺激素替代', '左甲状腺素钠为人工合成的四碘甲状腺原氨酸（T4），进入体内后与内源性T4同样，在靶组织（心、肝、肾、骨骼肌等）经I型或II型脱碘酶转化为活性形式三碘甲状腺原氨酸（T3）。T3与细胞核内甲状腺激素受体（TR）结合，调控靶基因转录，促进基础代谢率、蛋白质合成、生长发育和产热效应。对心血管系统可增强心肌收缩力和心率，降低外周血管阻力。', '口服吸收不完全且变异大，生物利用度犬约10-50%，空腹给药吸收更佳。吸收后99%以上与血浆蛋白（TBG、白蛋白、TTR）结合，游离激素仅约0.02%。在肝脏经葡萄糖醛酸化和硫酸化代谢，部分经脱碘酶转化为T3或反T3（rT3）。半衰期犬约12-16小时、猫约6-12小时。T4血浆浓度达稳态需4-6周，剂量调整应间隔4周以上复查。', '["犬甲状腺功能减退"]', '["甲状腺功能亢进", "肾上腺皮质功能减退（需先补充糖皮质激素）", "未纠正的肾上腺功能不全"]', '["多动/焦虑", "多饮多尿", "心动过速", "体重下降（过量时）"]', '医源性甲状腺功能亢进因替代剂量过高，导致代谢率过度升高。心血管不良反应因T3增强心肌β-肾上腺素能受体敏感性，增加心肌耗氧量和心率，可诱发或加重心律失常。体重减轻和肌肉消耗因蛋白质分解代谢增加。多饮多尿因肾血流量增加致肾小球滤过率升高。', '{"犬": "dose=0.02 mg/kg, route=PO, frequency=q12h", "猫": "dose=不适用（猫甲减极罕见）, route=-, frequency=-"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_009', '奥美拉唑', 'Omeprazole', '质子泵抑制剂（PPI）', '奥美拉唑为苯并咪唑类质子泵抑制剂（PPI），本身为弱碱前药，在胃壁细胞分泌小管的强酸性环境（pH<2）中转化为活性次磺酰胺衍生物，与H⁺/K⁺-ATP酶（质子泵）α亚基上的半胱氨酸残基形成二硫键，不可逆地抑制质子泵活性，阻断胃酸分泌的最后共同通路。由于质子泵再生需48-72小时，单次给药抑酸作用可持续24小时以上。对基础胃酸和刺激后胃酸均有强效抑制作用。', '口服后在小肠碱性环境中迅速吸收，生物利用度犬约30-40%（首过效应明显）。血浆蛋白结合率>95%，在肝脏经CYP2C19和CYP3A4代谢为无活性代谢物。半衰期犬约1小时（猫约1.5小时），但药效持续时间远超半衰期，因与质子泵不可逆结合。肠溶制剂需整粒吞服，避免胃酸降解。连续给药3-5天达稳态抑酸效果。', '["胃酸相关疾病", "消化性溃疡", "NSAIDs胃保护", "胰腺炎辅助", "胃食管反流"]', '["严重肝功能不全（需减量）"]', '["胃肠道反应（少见）", "长期用可能影响钙吸收"]', '胃酸屏障功能降低导致胃肠道感染风险增加，因胃酸杀菌作用减弱。高胃泌素血症因胃酸抑制后G细胞反馈性增生，长期可致肠嗜铬样细胞（ECL）增生。维生素B12和镁吸收减少因胃酸不足影响食物中营养素释放和吸收。罕见肝毒性因CYP450代谢产生的活性中间体。', '{"犬": "dose=0.5-1 mg/kg, route=PO, frequency=q24h（空腹给药）", "猫": "dose=0.7-1 mg/kg, route=PO, frequency=q24h（空腹给药）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_010', '马罗匹坦', 'Maropitant (Cerenia)', 'NK-1受体拮抗剂（止吐药）', '马罗匹坦为神经激肽-1（NK-1）受体高选择性拮抗剂，通过竞争性阻断P物质与NK-1受体结合，抑制呕吐中枢（孤束核和最后区）的激活。P物质是呕吐反射中关键的神经递质，在化学感受器触发区（CTZ）、胃肠道迷走神经传入纤维和中枢呕吐通路中均有分布。马罗匹坦可透过血脑屏障，在中枢和外周双重阻断呕吐信号传导，对中枢性和外周性呕吐均有效。', '口服生物利用度犬约25-30%（首过效应显著），皮下注射生物利用度>90%。血浆蛋白结合率>95%，主要分布于中枢神经系统。在肝脏经CYP3A4和CYP2D15（犬特异性）代谢，半衰期犬约8-12小时。主要经肝脏代谢后由胆汁排泄。犬可每日一次给药，中枢NK-1受体占据率高，止吐效果持续24小时。16周龄以下犬因血脑屏障发育不全禁用。', '["急性呕吐", "晕动症（犬）", "化疗相关呕吐", "胰腺炎辅助止吐"]', '["16周龄以下犬", "胃肠道梗阻", "严重肝功能不全"]', '["注射部位疼痛（SC）", "流涎（犬）", "腹泻", "食欲下降"]', '注射部位疼痛因注射液pH偏低（约2.5）刺激皮下组织。流涎为犬特有反应，可能与药物对中枢呕吐相关核团的短暂刺激有关。腹泻因NK-1受体阻断影响胃肠道正常运动和分泌功能。食欲下降与中枢食欲调节通路受影响有关。严重肝功能不全时药物清除减慢，不良反应风险增加。', '{"犬": "dose=1 mg/kg SC 或 2 mg/kg PO, route=SC/PO, frequency=q24h（不超过5天连续SC）", "猫": "dose=1 mg/kg, route=SC/PO, frequency=q24h（猫标签外使用）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_011', '曲马多', 'Tramadol', '阿片类镇痛药（弱）', '曲马多为中枢性镇痛药，具有双重作用机制：①弱μ-阿片受体激动剂，与μ受体亲和力约为吗啡的1/6000，产生轻度阿片样镇痛效应；②抑制突触前膜5-羟色胺（5-HT）和去甲肾上腺素（NE）再摄取，增强下行抑制性疼痛调节通路活性。两种机制协同产生镇痛效果，对慢性疼痛和术后疼痛均有效。在体内经CYP2D6代谢为活性代谢物O-去甲基曲马多（M1），后者μ受体亲和力为母药的200倍。', '口服吸收迅速完全，生物利用度犬约70-80%。血浆蛋白结合率约20%，分布容积大，可穿透血脑屏障。在肝脏经CYP3A4和CYP2D6代谢，半衰期犬约4-6小时、猫约6-8小时（猫CYP2D6活性低，M1生成少，镇痛效果可能减弱）。主要经肾脏排泄。需每日2-3次给药维持镇痛效果。与NSAIDs联用可产生协同镇痛。', '["中度疼痛", "术后疼痛", "骨关节炎疼痛", "慢性疼痛管理"]', '["癫痫病史", "与MAO抑制剂合用", "严重肝肾功能不全"]', '["镇静", "恶心/呕吐", "便秘", "瞳孔缩小", "唾液分泌增加（猫）"]', '恶心呕吐因μ受体激动和5-HT增加刺激化学感受器触发区。镇静和共济失调因中枢阿片受体和5-HT/NE系统调节改变。癫痫阈值降低因5-HT综合征风险和去甲肾上腺素能活性增强，与癫痫药物合用时需谨慎。便秘因肠道μ受体激动减少肠蠕动。猫可能出现瞳孔散大因中枢5-HT能活性增强。', '{"犬": "dose=2-5 mg/kg, route=PO, frequency=q8-12h", "猫": "dose=2-4 mg/kg, route=PO, frequency=q12h（猫代谢个体差异大）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_012', '美洛昔康', 'Meloxicam', 'NSAIDs（COX-2选择性抑制剂）', '美洛昔康为烯醇酸类非甾体抗炎药（NSAID），选择性抑制环氧化酶-2（COX-2），减少前列腺素E2（PGE2）和前列环素（PGI2）的合成，发挥抗炎、镇痛和解热作用。对COX-1抑制作用较弱，因此在治疗剂量下对胃肠道黏膜保护性前列腺素和血小板血栓素A2的影响较小。COX-2选择性在犬中较高（COX-2/COX-1 IC50比值约0.07），但在猫中选择性降低，需谨慎使用。', '口服吸收完全，生物利用度犬约90%以上、猫约70-80%。血浆蛋白结合率>95%，主要分布于炎症组织。在肝脏经CYP450酶系代谢为无活性代谢物，半衰期犬约24小时、猫约12-15小时（猫个体差异大）。犬可每日一次给药，猫建议初始剂量后减半维持。主要经粪便排泄（约75%），少量经肾脏排泄。', '["骨关节炎疼痛", "术后镇痛", "软组织损伤", "慢性炎症"]', '["脱水/低血容量", "消化道溃疡", "肾功能不全", "肝功能不全", "与其他NSAIDs或糖皮质激素合用"]', '["胃肠道溃疡/呕吐/腹泻", "肾毒性", "肝毒性", "凝血障碍"]', '胃肠道溃疡因COX-1在治疗剂量下仍有一定程度抑制，减少胃黏膜保护性PGE2合成。肾毒性因肾脏COX-2抑制导致肾血流量减少，尤其在低血容量或肾功能不全患畜中风险显著增加。肝毒性罕见但可能发生，与特异质免疫反应或代谢中间体蓄积有关。猫因半衰期延长和CYP代谢差异，毒性风险更高。', '{"犬": "dose=0.1 mg/kg, route=PO, frequency=q24h（首剂可0.2 mg/kg）", "猫": "dose=0.05 mg/kg, route=PO/SC, frequency=q24h（猫单次SC注射后转为口服，不超过3天）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_013', '多西环素', 'Doxycycline', '抗生素（四环素类）', '多西环素为半合成四环素类抗生素，通过与细菌30S核糖体亚基A位点可逆结合，阻止氨酰tRNA与mRNA-核糖体复合物结合，抑制细菌蛋白质合成，发挥抑菌作用。对革兰阳性菌、革兰阴性菌、立克次体、支原体、衣原体和螺旋体均有抗菌活性。此外具有免疫调节作用，可抑制基质金属蛋白酶（MMP）活性，减少炎症组织破坏。抗菌活性强于四环素和土霉素。', '口服吸收迅速，生物利用度犬约70-90%、猫约60-80%，受食物影响小（不同于其他四环素类）。脂溶性高，组织穿透力强，可穿透前列腺、中枢神经系统和骨组织。血浆蛋白结合率>90%，在肝脏代谢少，主要经胆汁排泄入肠腔形成肝肠循环，半衰期犬约8-12小时、猫约6-10小时。肾功能不全时无需显著调整剂量。', '["立克次体病（埃立克体、落基山斑疹热）", "支原体/衣原体感染", "莱姆病", "钩端螺旋体病", "心丝虫辅助"]', '["妊娠", "8周龄以下幼畜（牙齿着色风险）", "严重肝功能不全"]', '["食管狭窄（猫，给药后需冲水）", "呕吐/腹泻", "光敏反应", "肝毒性（罕见）"]', '食管狭窄因片剂滞留食管释放高浓度药物腐蚀黏膜，需给药后喂水。胃肠道反应因药物扰乱肠道菌群和直接刺激胃肠道黏膜。光敏性因药物在皮肤蓄积后吸收紫外线产生自由基。幼畜牙齿和骨骼沉积因与钙离子螯合沉积于钙化组织。肝毒性在大剂量时可能出现。', '{"犬": "dose=5-10 mg/kg, route=PO, frequency=q12h（首剂加倍）", "猫": "dose=5 mg/kg, route=PO, frequency=q12h（给药后冲水防食管狭窄）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_014', '甲硝唑', 'Metronidazole', '抗生素/抗原虫（硝基咪唑类）', '甲硝唑为硝基咪唑类抗菌和抗原虫药物，其硝基在厌氧菌和原虫体内低氧化还原电位环境中被铁氧还蛋白等电子载体还原，生成高活性的硝基自由基中间体和亚硝基衍生物。这些活性代谢物与DNA双链共价结合，引起DNA链断裂和螺旋结构破坏，抑制核酸合成，导致细胞死亡。对专性厌氧菌（梭杆菌、拟杆菌等）和原虫（贾第鞭毛虫、毛滴虫）具有选择性毒性，对需氧菌无效。', '口服吸收良好，生物利用度犬约75-90%、猫约70-80%，食物可轻微延缓吸收。脂溶性高，广泛分布于全身组织，能穿透血脑屏障（脑脊液浓度达血浆的50-100%）、骨组织和脓肿腔。在肝脏经氧化和葡萄糖醛酸化代谢，主要代谢物具弱抗菌活性。半衰期犬约4-8小时、猫约5-10小时。主要经肾脏排泄（约60-80%），肝功能不全时需减量。', '["厌氧菌感染", "贾第鞭毛虫", "炎症性肠病（免疫调节）", "肝性脑病", "坏死性肠炎"]', '["妊娠（早期）", "严重肝病", "与华法林合用"]', '["神经毒性（高剂量，共济失调/眼球震颤）", "食欲下降", "呕吐", "肝毒性（高剂量）"]', '神经毒性（共济失调、眼球震颤、癫痫）因活性代谢物损伤小脑和脑干神经元，与剂量累积相关，多见于长期大剂量使用时。胃肠道反应因药物直接刺激和肠道菌群失调。肝毒性因CYP450代谢产生的活性中间体。苦味反应为犬猫特有，因药物经唾液分泌。致畸性因DNA损伤作用，妊娠期禁用。', '{"犬": "dose=10-15 mg/kg, route=PO, frequency=q12h", "猫": "dose=10-15 mg/kg, route=PO, frequency=q12h（猫更易出现神经毒性）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_015', '地高辛', 'Digoxin', '强心苷类正性肌力药', '地高辛为强心苷类正性肌力药，通过抑制心肌细胞膜上的Na⁺/K⁺-ATP酶（钠钾泵），减少钠离子外流，导致细胞内钠离子浓度升高，进而通过Na⁺/Ca²⁺交换体（NCX）反向转运减少钙离子外排，使细胞内钙离子浓度升高，增强心肌收缩力（正性肌力作用）。同时通过增强迷走神经张力，减慢房室结传导（负性传导作用），降低窦房结自律性（负性频率作用），用于治疗快速性房颤。', '口服生物利用度犬约60-80%，起效时间1-2小时，达峰时间2-6小时。分布容积大（犬约10-15 L/kg），广泛分布于心肌、骨骼肌和脂肪组织，心肌浓度远高于血浆。主要经肾脏以原型排泄（60-90%），半衰期犬约24-48小时、猫约30-60小时。治疗窗窄（治疗浓度0.8-2.0 ng/mL），需监测血药浓度。肾功能不全时清除率降低，需减量。', '["充血性心力衰竭", "心房颤动（心室率控制）", "室上性心动过速"]', '["心室颤动", "肥厚型心肌病", "二度/三度房室传导阻滞", "低钾血症", "肾功能不全（需减量）"]', '["心律失常（治疗窗窄）", "厌食/呕吐/腹泻", "嗜睡", "视觉障碍"]', '心脏毒性（心律失常）因Na⁺/K⁺-ATP酶过度抑制导致细胞内钙超载和延迟后除极，低钾血症时心肌对地高辛敏感性显著增加。胃肠道反应因延髓化学感受器触发区刺激和直接肠道作用。神经系统反应（视觉异常）因视网膜感光细胞Na⁺/K⁺-ATP酶抑制。治疗指数窄，中毒浓度与治疗浓度重叠。', '{"犬": "dose=0.0025-0.005 mg/kg, route=PO, frequency=q12h（监测血药浓度）", "猫": "dose=0.001-0.002 mg/kg, route=PO, frequency=q24-48h（猫极敏感）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_016', '苯巴比妥', 'Phenobarbital', '抗癫痫药（巴比妥类）', '苯巴比妥为长效巴比妥类抗癫痫药，通过延长γ-氨基丁酸（GABA）与GABA_A受体结合后氯离子通道的开放时间（低剂量）和增加开放频率（高剂量），增强GABA能抑制性神经传递，导致神经元超极化，降低兴奋性。高剂量时还可抑制谷氨酸AMPA受体介导的兴奋性传递，并抑制电压门控钠通道和T型钙通道，全面降低神经元异常放电。对全身性强直-阵挛发作和部分性发作均有效。', '口服吸收缓慢但完全，生物利用度犬约80-90%。血浆蛋白结合率约45%，分布容积约0.7 L/kg。约25%经肝脏CYP450酶系（CYP2C/3A）代谢，其余以原型经肾脏排泄。半衰期犬约40-90小时（个体差异大，猫约35-50小时）。因半衰期长，达稳态需2-3周，犬可每日一次或两次给药。具肝酶诱导作用，可加速自身和其他药物代谢。', '["癫痫（一线用药）", "特发性癫痫", "癫痫持续状态（IV地西泮控制后维持）"]', '["严重肝病", "严重呼吸抑制"]', '["镇静/共济失调（初期）", "多饮多尿多食", "肝毒性（长期）", "血液学毒性（罕见）"]', '镇静和共济失调因GABA能抑制增强导致中枢神经系统普遍抑制。肝毒性因CYP450酶诱导产生肝毒性代谢中间体，长期用药可致肝纤维化和肝硬化。多饮多食多尿因抗利尿激素敏感性降低和代谢率改变。再生障碍性贫血罕见但严重，与免疫介导的骨髓抑制有关。突然停药可诱发癫痫持续状态。', '{"犬": "dose=2-5 mg/kg, route=PO, frequency=q12h（需监测血药浓度）", "猫": "dose=2-3 mg/kg, route=PO, frequency=q12h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_017', '溴化钾', 'Potassium Bromide', '抗癫痫药', '溴化钾为无机溴化物抗癫痫药，溴离子（Br⁻）与氯离子（Cl⁻）竞争通过GABA_A受体相关的氯离子通道，因溴离子的电导率低于氯离子，导致神经元膜超极化程度增加，提高神经元兴奋性阈值，抑制异常放电的扩散。对癫痫灶本身无直接作用，主要通过提高发作阈值来减少癫痫发作频率和严重程度。作为苯巴比妥的辅助用药，两者机制互补，可减少苯巴比妥用量。', '口服吸收迅速完全，生物利用度>90%。溴离子分布于全身体液（分布容积约0.3-0.5 L/kg），可穿透血脑屏障但速度慢于氯离子。不与血浆蛋白结合，完全以离子形式存在。几乎全部经肾脏排泄（肾小管重吸收率约50%），半衰期犬约24-46天（极长），达稳态需3-4个月。高氯饮食可加速溴离子排泄。需先给予负荷剂量再维持，定期监测血清溴浓度（治疗范围100-200 mg/dL）。', '["癫痫（单药或联合苯巴比妥）", "苯巴比妥不耐受的癫痫病例"]', '["肾功能不全", "对溴化物过敏"]', '["镇静/共济失调", "多饮多尿", "胰腺炎（犬）", "皮肤疹"]', '镇静和共济失调因中枢神经系统超极化抑制，多在治疗初期出现，通常数周后耐受。胃肠道刺激（恶心、呕吐）因溴离子直接刺激胃黏膜，与食物同服可减轻。溴中毒（精神错乱、肌阵挛、皮疹）因血清溴浓度超过250 mg/dL，肾脏排泄能力饱和。多饮多尿因溴离子干扰肾小管浓缩功能。', '{"犬": "dose=30-40 mg/kg, route=PO, frequency=q24h（负荷剂量可加倍）", "猫": "dose=不适用（猫溴化物可致致命性肺炎）, route=-, frequency=-"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_018', '阿莫西林', 'Amoxicillin', '抗生素（β-内酰胺类，氨基青霉素）', '阿莫西林为氨基青霉素类β-内酰胺抗生素，其β-内酰胺环结构与细菌青霉素结合蛋白（PBP）共价结合，抑制转肽酶活性，阻断肽聚糖链的交联反应，导致细菌细胞壁结构缺陷。在渗透压作用下水分内渗，细菌膨胀裂解死亡。对需氧革兰阳性菌（链球菌、葡萄球菌不产酶株）和部分革兰阴性菌（大肠埃希菌、变形杆菌不产酶株）有效，属时间依赖性杀菌剂。', '口服吸收迅速，生物利用度犬约75%、猫约60%，食物对吸收影响较小。广泛分布于组织液和体液，可穿透胎盘屏障，脑脊液浓度低（脑膜炎时可升高）。几乎不被肝脏代谢，主要以原型经肾小管分泌排泄，半衰期约1-1.5小时。属时间依赖性抗菌药，T>MIC为关键PK/PD参数，需每日两次给药维持有效血药浓度。', '["尿路感染", "皮肤感染", "呼吸道感染", "牙科感染", "软组织感染"]', '["青霉素过敏"]', '["胃肠道反应", "过敏反应", "肠道菌群失调"]', '胃肠道反应因药物扰乱肠道正常菌群，条件致病菌过度生长。过敏反应由β-内酰胺环降解产物作为半抗原与载体蛋白结合引发IgE介导的超敏反应，交叉过敏见于其他青霉素类。大剂量可致中枢神经兴奋（肌阵挛、癫痫），与GABA受体竞争性抑制有关。偶见结晶尿和间质性肾炎。', '{"犬": "dose=11-22 mg/kg, route=PO, frequency=q12h", "猫": "dose=11-22 mg/kg, route=PO, frequency=q12h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_019', '头孢氨苄', 'Cefalexin', '抗生素（第一代头孢菌素）', '头孢氨苄为第一代头孢菌素类抗生素，其β-内酰胺环与细菌青霉素结合蛋白（PBP-1和PBP-3）结合，抑制肽聚糖合成的最后交联步骤，导致细菌细胞壁缺陷而溶菌死亡。对革兰阳性菌（链球菌、不产酶葡萄球菌）抗菌活性强，对部分革兰阴性菌（大肠埃希菌、克雷伯菌不产酶株）亦有一定活性。对β-内酰胺酶不稳定，易被水解失活。', '口服吸收良好，生物利用度犬约70-80%，食物对吸收影响较小。广泛分布于组织和体液，但脑脊液浓度低。主要以原型经肾小管分泌排泄，半衰期犬约1-2小时、猫约1.5-2.5小时。属时间依赖性抗菌药，需每日2-3次给药维持T>MIC。', '["皮肤感染", "尿路感染", "软组织感染", "骨关节感染"]', '["青霉素/头孢菌素过敏", "严重肾功能不全（需调整剂量）"]', '["胃肠道反应", "过敏反应", "注射部位疼痛（IM）"]', '胃肠道反应因肠道菌群失调，表现为呕吐和腹泻。过敏反应较青霉素类少见，但交叉过敏率约5-10%。偶见结晶尿和肾小管损伤，大剂量使用时需注意水化。罕见粒细胞减少和嗜酸性粒细胞增多，与免疫介导机制有关。', '{"犬": "dose=22-30 mg/kg, route=PO, frequency=q12h", "猫": "dose=22-30 mg/kg, route=PO, frequency=q12h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_020', '氟苯尼考', 'Florfenicol', '抗生素（苯丙醇类）', '氟苯尼考为苯丙醇类广谱抑菌性抗生素，通过与细菌50S核糖体亚基可逆结合，抑制肽酰转移酶活性，阻断肽链延伸，抑制细菌蛋白质合成。抗菌谱覆盖革兰阳性菌、革兰阴性菌、支原体和立克次体，对部分肠杆菌科细菌亦有效。与氯霉素结构相似但不具硝基，因此不引起再生障碍性贫血。属动物专用兽药，禁止用于食品动物泌乳期。', '口服吸收良好，生物利用度犬约70-90%。脂溶性高，组织穿透力强，能穿透血脑屏障、前列腺和骨组织。在肝脏经葡萄糖醛酸化代谢为无活性代谢物，半衰期犬约3-5小时。主要经肾脏排泄（约60-70%），少量经胆汁排泄。属浓度依赖性抗菌药，建议每日一次或两次给药。', '["呼吸道感染（尤其牛呼吸道病）", "皮肤感染", "多药耐药菌感染"]', '["妊娠", "疫苗接种期间", "家禽（禁用）"]', '["胃肠道反应", "骨髓抑制（罕见）", "注射部位反应"]', '骨髓抑制为最严重不良反应，因抑制线粒体蛋白合成导致可逆性红细胞生成抑制，与剂量相关。胃肠道反应因肠道菌群失调。肝毒性罕见，与代谢中间体蓄积有关。免疫抑制作用因高剂量时抑制抗体生成。局部注射部位可出现组织刺激和炎症反应。', '{"犬": "dose=20 mg/kg, route=PO/SC, frequency=q8-12h", "猫": "dose=标签外使用，数据有限, route=PO, frequency=谨慎使用"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_021', '特比萘芬', 'Terbinafine', '抗真菌药（丙烯胺类）', '特比萘芬为丙烯胺类抗真菌药，通过选择性抑制角鲨烯环氧酶，阻断麦角固醇生物合成途径。角鲨烯在真菌细胞内蓄积产生细胞毒性，同时麦角固醇缺乏导致细胞膜功能障碍，对皮肤癣菌有杀菌作用。', '口服吸收约40-50%，高脂餐促进吸收。高度亲脂性，在皮肤、毛发和指甲中浓度远高于血浆。血浆蛋白结合率>99%，半衰期约12小时。主要经肝脏CYP450代谢。', '["皮肤真菌病（癣菌）", "甲真菌病", "马拉色菌感染"]', '["严重肝功能不全"]', '["胃肠道反应", "肝酶升高", "味觉障碍（罕见）"]', '胃肠道反应（呕吐、腹泻、厌食）。肝酶升高（罕见肝毒性，需监测）。味觉障碍。皮疹。', '{"犬": "dose=30 mg/kg, route=PO, frequency=q24h", "猫": "dose=20-40 mg/kg, route=PO, frequency=q24h（猫对疗程要求更长）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_022', '伊曲康唑', 'Itraconazole', '抗真菌药（三唑类）', '伊曲康唑为三唑类抗真菌药，抑制真菌细胞色素P450依赖的14α-去甲基酶，阻断麦角固醇合成，导致细胞膜通透性改变。对皮肤癣菌、念珠菌、曲霉菌、组织胞浆菌等均有活性。', '口服吸收受胃酸影响，酸性环境和食物促进吸收。高度亲脂性，在皮肤和角质层中浓度极高。血浆蛋白结合率>99%，半衰期约12-15小时。主要经肝脏CYP450代谢，为CYP3A4抑制剂。', '["深部真菌病（组织胞浆菌、球孢子菌、隐球菌）", "皮肤真菌病", "曲霉菌病"]', '["严重肝病", "妊娠", "与某些心脏药物合用"]', '["肝毒性", "胃肠道反应", "皮肤溃疡（犬脉冲疗法时）", "食欲下降"]', '胃肠道反应（厌食、呕吐）。肝毒性（剂量依赖性，需监测肝酶）。与多种药物有相互作用（CYP450抑制）。负性肌力作用（慎用于心功能不全）。', '{"犬": "dose=5-10 mg/kg, route=PO, frequency=q12-24h（与食物同服）", "猫": "dose=5-10 mg/kg, route=PO, frequency=q24h（液体剂型优于胶囊）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_023', '多拉西泮（安定）', 'Diazepam', '苯二氮卓类', '地西泮为苯二氮卓类药物，与GABA_A受体上的苯二氮卓位点结合，增强GABA与受体的亲和力，增加氯离子通道开放频率，产生镇静、抗焦虑、肌肉松弛和抗惊厥作用。', '口服吸收迅速，生物利用度约90%。肌肉注射吸收不稳定。血浆蛋白结合率>98%，半衰期约2-4小时。主要经肝脏代谢为活性代谢物（去甲西泮、奥沙西泮）。', '["癫痫持续状态（IV）", "焦虑/行为问题", "术前镇静", "骨骼肌痉挛", "猫特发性膀胱炎（急性期）"]', '["严重肝功能不全（猫口服可致致命性肝坏死）", "重症肌无力", "严重呼吸抑制"]', '["镇静/共济失调", "肝毒性（猫口服）", "兴奋性矛盾反应（猫）", "呼吸抑制（IV）"]', '镇静、共济失调。矛盾性兴奋（罕见）。猫罕见但严重的特发性肝衰竭。长期使用产生耐受性和依赖性。', '{"犬": "dose=0.5-2 mg/kg IV（癫痫持续状态）；0.2-0.5 mg/kg PO, route=IV/PO, frequency=按需", "猫": "dose=0.5-1 mg/kg IV（癫痫持续状态）, route=IV, frequency=按需（避免口服，肝毒性风险）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_024', '阿替美唑', 'Atipamezole', 'α-2肾上腺素能受体拮抗剂（右美托咪定拮抗剂）', '阿替美唑为高选择性α-2肾上腺素能受体拮抗剂，通过竞争性阻断α-2受体，逆转美托咪定等α-2激动剂引起的镇静、镇痛和心血管抑制效应。作为特异性拮抗剂使用。', '肌肉注射吸收迅速，5-10分钟起效。血浆蛋白结合率约85%，半衰期约1-2小时。主要经肝脏代谢。', '["右美托咪定/美托咪定麻醉后逆转", "镇静逆转"]', '["妊娠", "心脏病（相对）"]', '["短暂性低血压", "呕吐", "兴奋/躁动", "心动过速"]', '短暂性低血压或高血压。兴奋、震颤。快速逆转可能导致急性疼痛。流涎。', '{"犬": "dose=与右美托咪定等量（mg）, route=IM, frequency=单次", "猫": "dose=与右美托咪定等量（mg）, route=IM, frequency=单次"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_025', '纳洛酮', 'Naloxone', '阿片受体拮抗剂', '纳洛酮为阿片受体非选择性拮抗剂，通过竞争性阻断μ、κ、δ阿片受体，快速逆转阿片类药物引起的呼吸抑制、镇静和镇痛效应。作为阿片类药物过量的特效解毒剂。', '静脉注射1-2分钟起效，肌肉注射5-10分钟起效。血浆蛋白结合率约45%，半衰期约1-1.5小时（短于多数阿片类药物，可能需重复给药）。主要经肝脏葡萄糖醛酸化代谢。', '["阿片类药物过量逆转", "术后阿片类药物残余效应"]', '["阿片类药物依赖动物（可诱发戒断）"]', '["疼痛反弹", "心动过速", "兴奋/躁动", "肺水肿（罕见，快速IV）"]', '急性戒断症状（阿片依赖动物）：烦躁、呕吐、腹泻。疼痛快速恢复。心血管反应（高血压、心律失常、肺水肿）。', '{"犬": "dose=0.01-0.04 mg/kg, route=IV/IM/SC, frequency=可重复（作用时间短于阿片类）", "猫": "dose=0.01-0.04 mg/kg, route=IV/IM/SC, frequency=可重复"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_026', '维生素K1', 'Phytonadione (Vitamin K1)', '维生素/凝血因子合成辅助', '维生素K1（植物甲萘醌）为脂溶性维生素，作为γ-谷氨酰羧化酶的辅因子，参与凝血因子II、VII、IX、X以及蛋白C和蛋白S的γ-羧化过程，使其具有凝血活性。用于抗凝血类杀鼠药（华法林类）中毒的特效解毒。', '口服吸收需要胆汁乳化，皮下注射吸收更稳定。血浆蛋白结合率高，半衰期约1-2小时。主要在肝脏代谢。', '["香豆素类灭鼠药中毒", "华法林过量", "严重肝病凝血障碍", "新生畜维生素K缺乏"]', '["无特殊绝对禁忌"]', '["过敏反应（IV）", "注射部位反应", "高铁血红蛋白血症（极高剂量）"]', '注射部位反应（疼痛、肿胀）。罕见过敏反应（静脉注射时风险较高，建议皮下或口服给药）。过量可致血栓风险。', '{"犬": "dose=2-5 mg/kg, route=PO/SC, frequency=q12-24h（随脂餐口服）；疗程2-4周（灭鼠药中毒）", "猫": "dose=2-5 mg/kg, route=PO/SC, frequency=q12-24h（猫对灭鼠药更敏感）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_027', '硫糖铝', 'Sucralfate', '胃黏膜保护剂', '硫糖铝在胃酸（pH<4）作用下解离为带负电荷的八硫酸蔗糖，与溃疡面带正电荷的蛋白质结合形成粘稠凝胶，选择性粘附于溃疡组织形成保护屏障。促进内源性前列腺素E2和表皮生长因子合成，增强粘膜防御和修复。', '口服后几乎不吸收（<5%），局部作用于胃黏膜。不被代谢，以原形随粪便排出。', '["消化道溃疡", "NSAIDs相关胃损伤", "尿毒症胃炎", "食管炎"]', '["严重肾功能不全（铝蓄积风险）"]', '["便秘", "铝蓄积（长期/肾衰）", "影响其他药物吸收（需间隔2h）"]', '便秘最常见（约2-5%）。罕见铝蓄积（长期使用于肾功能不全动物）。可能影响其他药物吸收（需间隔2小时给药）。', '{"犬": "dose=0.5-1 g, route=PO, frequency=q8-12h（空腹）", "猫": "dose=0.25 g, route=PO, frequency=q8-12h（空腹）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_028', '多库酯钠', 'Docusate Sodium (DSS)', '粪便软化剂/灌肠剂', '多库酯钠为阴离子表面活性剂，降低粪便表面张力，使水分和脂肪渗入粪便，软化粪便并促进排出。同时可刺激肠壁神经丛促进肠蠕动。作为粪便软化剂使用。', '口服后几乎不吸收，局部作用于肠道。以原形随粪便排出。', '["便秘", "巨结肠（猫）", "粪便嵌塞", "灌肠（DSS灌肠液）"]', '["肠梗阻", "消化道穿孔"]', '["腹泻", "电解质紊乱（长期口服）", "灌肠时黏膜刺激"]', '胃肠道反应（恶心、腹痛、腹泻、里急后重）。罕见电解质紊乱。', '{"犬": "dose=50-200 mg, route=PO, frequency=q12-24h", "猫": "dose=50 mg, route=PO, frequency=q24h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_029', '乳酸林格液', 'Lactated Ringer''s Solution', '晶体液（等渗）', '乳酸林格液为等渗晶体液，电解质成分与血浆相似（Na⁺ 130mEq/L, K⁺ 4mEq/L, Ca²⁺ 3mEq/L, Cl⁻ 109mEq/L, 乳酸根 28mEq/L）。乳酸根在肝脏代谢为碳酸氢根，有助于纠正轻度代谢性酸中毒。', '静脉输注后迅速分布至细胞外液。不引起渗透压异常。', '["脱水补液", "围手术期液体支持", "低血容量休克", "电解质紊乱纠正", "维持输液"]', '["高钙血症（含钙）", "严重乳酸酸中毒", "高钾血症"]', '["液体过负荷", "低钾血症（稀释性）", "静脉炎（外周输注）"]', '液体过负荷（尤其心功能不全或肾功能不全时可致肺水肿）。电解质稀释。乳酸根代谢障碍时（肝功能不全）可致代谢性碱中毒。', '{"犬": "dose=10-30 ml/kg/h（急性休克）；40-60 ml/kg/day（维持）, route=IV, frequency=持续", "猫": "dose=3-5 ml/kg/h（急性）；2-4 ml/kg/h（维持）, route=IV, frequency=持续（猫易过负荷）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_030', '活性炭', 'Activated Charcoal', '吸附剂（解毒）', '活性炭具有极大的比表面积（1000-2000 m²/g），通过物理吸附作用与胃肠道内的毒物分子结合，形成不溶性复合物，阻止毒物经肠壁吸收。在中毒后1-2小时内使用效果最佳，对吸附能力强的毒物（如有机磷、对乙酰氨基酚）效果显著。', '口服后完全不被吸收，以原形随粪便排出。', '["中毒急救（吸附胃肠道毒物）", "某些药物过量", "乙二醇中毒辅助"]', '["肠梗阻/穿孔", "腐蚀性物质中毒", "无保护气道（误吸风险）"]', '["呕吐/误吸", "便秘/肠梗阻", "高钠血症（含山梨醇制剂）", "黑便"]', '便秘。呕吐（尤其大量给药时，误吸风险）。可能吸附其他口服药物降低其疗效。对重金属、醇类、氰化物吸附效果差。', '{"犬": "dose=1-4 g/kg（首剂）, route=PO, frequency=q4-8h（含山梨醇制剂不超过2次）", "猫": "dose=1-4 g/kg（首剂）, route=PO, frequency=q4-8h（猫需更小体积，注意误吸风险）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_031', '托芬那酸', 'Tolfenamic Acid', 'NSAIDs（芬那酸类）', '托芬那酸为芬那酸类NSAID，通过抑制环氧化酶（COX），减少前列腺素合成，发挥抗炎、镇痛和解热作用。对COX-2有一定选择性，抗炎效果强。', '口服吸收良好。血浆蛋白结合率>99%，半衰期约3-4小时。主要经肝脏代谢。', '["术后镇痛", "骨关节炎", "软组织炎症", "发热（猫）"]', '["脱水/低血容量", "消化道溃疡", "肾功能不全", "肝功能不全", "妊娠"]', '["胃肠道反应", "肾毒性", "肝毒性", "注射部位反应（SC）"]', '胃肠道反应（呕吐、腹泻、溃疡）。肾毒性（尤其脱水时）。肝毒性。', '{"犬": "dose=4 mg/kg, route=SC/PO, frequency=单次SC或q24h PO（不超过3天）", "猫": "dose=4 mg/kg, route=SC, frequency=单次（猫仅批准单次SC注射）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_032', '加巴喷丁', 'Gabapentin', '抗癫痫药/神经性镇痛药', '加巴喷丁与电压门控钙通道的α2δ-1亚基结合，减少钙离子内流，抑制兴奋性神经递质（谷氨酸、P物质、降钙素基因相关肽）释放，降低神经元兴奋性。用于神经性疼痛管理和辅助抗癫痫治疗。', '口服吸收良好但剂量依赖性饱和（剂量增加时生物利用度下降，因肠道L-氨基酸转运体饱和）。不与血浆蛋白结合，半衰期约3-4小时。以原形经肾脏排泄。', '["神经性疼痛", "慢性疼痛（联合NSAIDs）", "术后镇痛辅助", "焦虑（猫术前）", "难治性癫痫辅助"]', '["严重肾功能不全（需减量）"]', '["镇静/共济失调", "外周水肿", "含Xylitol的口服液（犬禁用）"]', '镇静、共济失调（最常见，与剂量相关）。外周水肿。体重增加。', '{"犬": "dose=5-10 mg/kg, route=PO, frequency=q8-12h（镇痛）；3-5 mg/kg q8h（起始）", "猫": "dose=5-10 mg/kg, route=PO, frequency=q8-12h（镇痛/术前镇静）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_033', '氯胺酮', 'Ketamine', '分离麻醉剂（NMDA受体拮抗剂）', '氯胺酮为NMDA受体非竞争性拮抗剂，阻断谷氨酸的兴奋性传导，产生分离麻醉（意识与感觉分离）。同时抑制丘脑-皮层投射系统，激活边缘系统。增加交感神经活性，维持血压和心率。', '静脉注射30秒起效，肌肉注射3-5分钟起效。血浆蛋白结合率约20-30%，半衰期约1-2小时。主要经肝脏代谢为活性代谢物去甲氯胺酮（镇痛活性为母药的1/3-1/5）。', '["诱导麻醉", "镇痛（亚麻醉剂量）", "癫痫持续状态", "安乐死（辅助）"]', '["严重高血压", "颅内压升高", "严重肝病", "单独使用（需联合镇静剂）"]', '["唾液分泌增加", "肌肉僵直", "精神性反应（猫）", "呼吸抑制（高剂量）", "惊厥阈值降低"]', '唾液分泌增多（需合用阿托品减少分泌）。肌肉紧张、惊厥（恢复期）。颅内压和眼压升高。单独使用镇痛效果有限，常需与镇静剂联合。', '{"犬": "dose=5-10 mg/kg IV（诱导，联合镇静剂）, route=IV/IM, frequency=按需", "猫": "dose=5-10 mg/kg IV（诱导）, route=IV/IM, frequency=按需（猫可单独用于制动）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_034', '布托啡诺', 'Butorphanol', '阿片类镇痛药（激动-拮抗剂）', '布托啡诺为混合型阿片受体激动-拮抗剂：κ受体激动产生镇痛和镇静作用，μ受体部分激动/拮抗。镇痛效果约为吗啡的5倍，呼吸抑制有封顶效应（安全性优于纯μ激动剂）。', '肌肉注射10-15分钟起效，持续约4-6小时。血浆蛋白结合率约80%，半衰期约3-4小时。主要经肝脏代谢。', '["中度至重度疼痛", "术前镇痛", "术后镇痛", "内脏痛"]', '["严重肝肾功能不全", "与纯阿片激动剂合用（可拮抗其作用）"]', '["镇静", "流涎", "共济失调", "食欲下降", "呼吸抑制（高剂量）"]', '镇静。胃肠道反应（恶心、呕吐）。大剂量时可能出现烦躁不安。', '{"犬": "dose=0.2-0.4 mg/kg, route=IV/IM/SC, frequency=q2-4h（镇痛）；0.25-0.5 mg/kg PO q6-8h", "猫": "dose=0.2-0.4 mg/kg, route=IV/IM/SC, frequency=q2-4h（猫对布托啡诺敏感，镇痛效果好）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_035', '布地奈德', 'Budesonide', '糖皮质激素（局部作用）', '布地奈德为局部作用糖皮质激素，与胞浆内糖皮质激素受体结合后转入细胞核，抑制促炎基因转录，减少炎症介质产生。口服首过效应强（约90%在肝脏被快速代谢），因此吸入或局部给药时全身副作用显著减少。', '吸入给药时直接作用于气道黏膜。口服生物利用度约10%。血浆蛋白结合率约85-90%，半衰期约2-3小时。主要经肝脏CYP3A4代谢。', '["炎症性肠病（IBD）", "慢性肠病", "结肠炎"]', '["真菌感染", "妊娠", "对布地奈德过敏"]', '["医源性库欣（长期高剂量）", "肾上腺抑制", "胃肠道反应（少见）"]', '口腔念珠菌感染（局部免疫抑制）。声音嘶哑。长期高剂量全身吸收后可出现库欣样症状。', '{"犬": "dose=1-3 mg/只（小型犬1mg，大型犬3mg）, route=PO, frequency=q24h（逐渐减量）", "猫": "dose=1 mg/只, route=PO, frequency=q24h（猫IBD治疗）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_036', '司来吉兰', 'Selegiline (L-Deprenyl)', '单胺氧化酶-B抑制剂（MAO-B抑制剂）', '司来吉兰为选择性单胺氧化酶-B（MAO-B）抑制剂，抑制多巴胺的代谢降解，增加突触间隙多巴胺浓度。同时可能具有神经保护作用（减少氧化应激、抑制神经元凋亡）。用于犬认知功能障碍综合征和库欣综合征。', '口服吸收良好，生物利用度约10%（首过效应强）。血浆蛋白结合率约90%，半衰期约1-2小时。主要经肝脏代谢。', '["犬库欣综合征（垂体依赖型）", "犬认知功能障碍综合征（CDS）"]', '["与SSRI类抗抑郁药合用", "与哌替啶合用", "妊娠"]', '["呕吐/厌食", "焦虑/兴奋", "心动过速", "嗜睡", "耳部瘙痒"]', '胃肠道反应。失眠（建议早晨给药）。与哌替啶合用可致严重不良反应（5-羟色胺综合征）。', '{"犬": "dose=1 mg/kg, route=PO, frequency=q24h（库欣）；0.5-1 mg/kg q24h（CDS）", "猫": "dose=不适用（猫司来吉兰疗效未证实）, route=-, frequency=-"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_037', '曲唑酮', 'Trazodone', '5-HT受体拮抗剂/再摄取抑制剂（SARI类）', '曲唑酮为5-HT受体拮抗剂/再摄取抑制剂（SARI类），通过阻断5-HT2A受体和抑制5-HT再摄取，产生抗焦虑和镇静作用。同时阻断α-1肾上腺素能受体。用于犬猫行为问题管理。', '口服吸收良好。血浆蛋白结合率约89-95%，半衰期约5-9小时。主要经肝脏代谢为活性代谢物mCPP。', '["焦虑/行为问题", "术前镇静", "术后笼养镇静", "噪音恐惧症", "分离焦虑"]', '["与MAO抑制剂合用", "严重肝功能不全", "已知QT延长"]', '["镇静（最常见）", "共济失调", "胃肠道反应", "激越（少见）", "阴茎异常勃起（犬，未去势）"]', '镇静、共济失调。胃肠道反应。罕见阴茎异常勃起（犬）。与SSRI合用时需谨慎。', '{"犬": "dose=2-5 mg/kg, route=PO, frequency=q8-12h（镇静/焦虑）；术前2-3h给予5-10 mg/kg", "猫": "dose=50-100 mg/只, route=PO, frequency=q24h（猫标签外使用，数据有限）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_038', '贝那普利', 'Benazepril', '血管紧张素转换酶抑制剂（ACEI）', '贝那普利为血管紧张素转换酶抑制剂（ACEI），抑制血管紧张素I转化为血管紧张素II（强效血管收缩剂），同时减少缓激肽降解，产生血管扩张作用。降低心脏前后负荷，改善心输出量。', '口服后在肝脏水解为活性代谢物贝那普利拉。血浆蛋白结合率约95%，半衰期约10-12小时。主要经肾脏排泄。', '["慢性肾病（减少蛋白尿）", "心力衰竭辅助", "高血压"]', '["双侧肾动脉狭窄", "妊娠", "严重肾功能不全（需谨慎）", "低血压"]', '["低血压", "高钾血症", "食欲下降", "呕吐/腹泻", "肾功能恶化（罕见）"]', '低血压（尤其脱水或合用利尿剂时）。高钾血症。肾功能恶化。胃肠道反应。咳嗽（人医常见，兽医少见）。', '{"犬": "dose=0.25-0.5 mg/kg, route=PO, frequency=q24h", "猫": "dose=0.25-0.5 mg/kg, route=PO, frequency=q24h（猫CKD蛋白尿管理）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_039', '碳酸镧', 'Lanthanum Carbonate', '磷酸盐结合剂', '碳酸镧为非钙非金属磷酸盐结合剂，在胃肠道中与食物中的磷酸根结合形成不溶性磷酸镧复合物，阻止磷酸盐经肠壁吸收，从而降低血磷水平。用于慢性肾病高磷血症的管理。', '口服后几乎不吸收（<0.001%），局部作用于胃肠道。不与血浆蛋白结合，以原形随粪便排出。', '["高磷血症（CKD相关）", "慢性肾病矿物质代谢紊乱"]', '["低磷血症", "肠梗阻"]', '["胃肠道反应（恶心/呕吐）", "便秘", "电解质紊乱"]', '胃肠道反应（恶心、呕吐、便秘）。罕见铝样脑病（理论风险）。', '{"犬": "dose=30-90 mg/kg, route=PO, frequency=q24h（与食物同服）", "猫": "dose=30-60 mg/kg, route=PO, frequency=q24h（与食物同服）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_040', '乙酰丙嗪', 'Acepromazine', '吩噻嗪类镇静剂', '乙酰丙嗪为吩噻嗪类镇静剂，通过阻断多巴胺D2受体产生镇静和安定作用。同时具有抗组胺和抗胆碱能作用。作为术前镇静和化学保定用药。', '口服吸收良好。血浆蛋白结合率>90%，半衰期约3-6小时。主要经肝脏代谢。', '["术前镇静", "镇静/制动", "镇吐辅助", "化学保定"]', '["癫痫（降低惊厥阈值）", "严重心血管疾病", "妊娠", "拳师犬（易晕厥）", "老年/体弱动物"]', '["镇静", "低血压", "心动过缓", "低体温", "阴茎异常勃起/脱垂（未去势公犬，罕见但严重）"]', '镇静、低血压（α-1受体阻断）。体温调节障碍（环境温度敏感）。斗牛犬品系可致晕厥。降低癫痫阈值。', '{"犬": "dose=0.02-0.05 mg/kg, route=IV/IM/SC, frequency=按需（镇静）；0.5-2.2 mg/kg PO q6-8h", "猫": "dose=0.02-0.05 mg/kg, route=IV/IM/SC, frequency=按需（镇静）；1-2 mg/kg PO q8-12h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_041', '氯雷他定', 'Loratadine', '抗组胺药（H1受体拮抗剂，第二代）', '氯雷他定为第二代抗组胺药，选择性阻断外周H1受体，抑制组胺引起的血管扩张、毛细血管通透性增加和平滑肌收缩。不易穿透血脑屏障，因此中枢镇静作用轻微。', '口服吸收良好，生物利用度约40-50%（首过效应）。血浆蛋白结合率约97-99%，半衰期约8-12小时（活性代谢物去羧乙氧基氯雷他定半衰期更长）。主要经肝脏CYP3A4代谢。', '["过敏/特应性皮炎", "荨麻疹", "过敏性鼻炎", "跳蚤过敏性皮炎辅助"]', '["严重肝功能不全（需减量）"]', '["镇静（少见，第二代抗组胺药镇静作用轻）", "胃肠道反应", "口干"]', '轻微镇静（偶见）。胃肠道反应。罕见心动过速。', '{"犬": "dose=0.5-1 mg/kg, route=PO, frequency=q24h", "猫": "dose=5 mg/只, route=PO, frequency=q24h（猫标签外使用）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_042', '苯巴比妥', 'Phenobarbital', '抗癫痫药（巴比妥类）', '苯巴比妥为长效巴比妥类抗癫痫药，通过增强GABA_A受体介导的氯离子内流（延长氯通道开放时间），增强中枢抑制效应。同时抑制谷氨酸的AMPA受体活性，提高癫痫发作阈值。', '口服吸收良好，生物利用度约80-90%。血浆蛋白结合率约45%，半衰期约37-73小时（犬个体差异大）。强效肝药酶诱导剂（CYP450），可加速自身和其他药物代谢。', '["犬特发性癫痫", "癫痫持续状态（IV）", "猫癫痫（二线）"]', '["严重肝病", "妊娠", "与氯丙嗪合用（降低惊厥阈值）"]', '["镇静/共济失调（起始期常见）", "多饮多尿多食", "肝毒性（长期）", "再生障碍性贫血（罕见）"]', '镇静、多饮多尿、多食、体重增加（初期最常见）。肝毒性（长期使用需定期监测肝酶和血药浓度）。血液学毒性（罕见）。突然停药可诱发癫痫持续状态。', '{"犬": "dose=2-5 mg/kg, route=PO, frequency=q12h（维持）；20 mg/kg IV（癫痫持续状态）", "猫": "dose=2-3 mg/kg, route=PO, frequency=q12h（猫二线用药）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_043', '溴化钾', 'Potassium Bromide', '抗癫痫药（溴化物）', '溴化钾通过溴离子替代氯离子进入神经元，增加细胞膜超极化程度，降低神经元兴奋性，提高癫痫发作阈值。与苯巴比妥有协同作用，常作为二线或辅助抗癫痫药。不影响肝药酶。', '口服吸收良好，生物利用度约90%以上。不与血浆蛋白结合，半衰期极长（约24-46天），需给予负荷剂量加速达稳态。完全经肾脏排泄，肾功能不全时半衰期延长。', '["犬难治性癫痫（联合苯巴比妥）", "苯巴比妥不耐受时的替代"]', '["肾功能不全", "妊娠", "与含溴药物合用"]', '["镇静/共济失调（起始期）", "多饮多尿多食", "胃肠道反应", "皮肤反应（罕见）"]', '镇静、共济失调、虚弱（初期，通常1-2周后耐受）。胃肠道反应（恶心、呕吐）。多饮多尿。溴中毒（极高剂量）：意识模糊、精神病样行为、皮疹。', '{"犬": "dose=30-40 mg/kg, route=PO, frequency=q24h（维持）；负荷剂量200-300 mg/kg 分5天给予", "猫": "dose=不适用（猫溴化物耐受差，可致支气管痉挛）, route=-, frequency=-"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_044', '硫唑嘌呤', 'Azathioprine', '免疫抑制剂（嘌呤类似物）', '硫唑嘌呤为嘌呤类似物免疫抑制剂，在体内代谢为6-巯基嘌呤（6-MP），掺入DNA后抑制嘌呤从头合成，阻断淋巴细胞（尤其是T细胞）增殖。用于免疫介导性疾病的长期免疫抑制治疗。', '口服吸收良好。血浆蛋白结合率约30%，半衰期约3-5小时（但其活性代谢物作用时间更长）。主要经肝脏代谢。', '["免疫介导性疾病（IMHA/IMPA）", "炎症性肠病（激素节约剂）", "自身免疫性皮肤病"]', '["妊娠", "严重肝病", "与别嘌醇合用（毒性增加）"]', '["骨髓抑制（WBC↓）", "胃肠道反应", "肝毒性", "胰腺炎（犬）"]', '骨髓抑制（白细胞减少、血小板减少）是最严重不良反应。胃肠道反应（恶心、呕吐、腹泻）。肝毒性。胰腺炎（犬）。感染风险增加。', '{"犬": "dose=2 mg/kg, route=PO, frequency=q24h（诱导）；q48h（维持）", "猫": "dose=0.3 mg/kg, route=PO, frequency=q48-72h（猫对硫唑嘌呤敏感，代谢慢）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_045', '环磷酰胺', 'Cyclophosphamide', '烷化剂（化疗药）', '环磷酰胺为烷化剂类化疗药和免疫抑制剂，在肝脏被CYP450活化后产生磷酰胺氮芥，与DNA交联，阻断DNA复制和转录，抑制细胞增殖。对增殖活跃的淋巴细胞有选择性毒性。', '口服吸收良好，生物利用度约75-90%。血浆蛋白结合率低，半衰期约3-12小时。主要经肝脏活化，代谢物经肾脏排泄。', '["淋巴瘤（CHOP方案）", "免疫介导性疾病（严重）", "肿瘤化疗"]', '["妊娠", "严重骨髓抑制", "活动性感染", "严重肝病"]', '["骨髓抑制", "胃肠道反应", "出血性膀胱炎（犬）", "脱发（有毛品种）"]', '骨髓抑制（剂量限制性毒性）。胃肠道反应（恶心、呕吐）。出血性膀胱炎（代谢物丙烯醛刺激膀胱黏膜，需配合美司钠和充足饮水）。脱发。免疫抑制。', '{"犬": "dose=50 mg/m², route=PO, frequency=q48h（CHOP方案中）；200 mg/m² IV 每周一次", "猫": "dose=10 mg/kg, route=IV, frequency=每2-3周（猫CHOP方案剂量较低）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_046', '长春新碱', 'Vincristine', '植物碱类化疗药（长春花生物碱）', '长春新碱为长春花生物碱类化疗药，与微管蛋白结合，抑制微管聚合，阻断有丝分裂纺锤体形成，使细胞停滞于M期。同时干扰多种细胞器功能和蛋白质合成。', '静脉给药（不可鞘外注射，有组织坏死风险）。血浆蛋白结合率约75%，半衰期约1-2小时（但组织结合时间长，实际作用持续数天）。主要经肝脏CYP3A4代谢，经胆汁排泄。', '["淋巴瘤（CHOP方案）", "犬血小板减少症（ITP）"]', '["妊娠", "严重骨髓抑制", "肝静脉闭塞病"]', '["外周神经毒性", "胃肠道反应", "局部组织坏死（渗漏）", "骨髓抑制（较轻）"]', '骨髓抑制（较其他长春花生物碱轻）。外周神经毒性（感觉异常、便秘、肠梗阻）。局部组织坏死（外渗时）。胃肠道反应。脱发。', '{"犬": "dose=0.5-0.75 mg/m², route=IV, frequency=每周一次（CHOP方案）", "猫": "dose=0.5-0.7 mg/m², route=IV, frequency=每周一次（猫CHOP方案）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_047', '多柔比星', 'Doxorubicin', '蒽环类化疗药', '多柔比星为蒽环类化疗药，通过多种机制发挥抗肿瘤作用：①嵌入DNA双链，抑制拓扑异构酶II，阻断DNA复制；②产生自由基，导致DNA链断裂和细胞膜损伤；③抑制RNA合成。', '静脉给药（不可肌肉或皮下注射）。血浆蛋白结合率约75%，半衰期约1-2小时（终末半衰期更长）。主要经肝脏代谢，经胆汁排泄。', '["淋巴瘤（CHOP方案）", "血管肉瘤", "骨肉瘤", "多种实体瘤"]', '["心脏病（累积心脏毒性）", "严重肝病", "妊娠", "累积剂量限制"]', '["骨髓抑制", "心脏毒性（累积剂量相关）", "胃肠道反应", "局部组织坏死（渗漏）", "脱毛"]', '心脏毒性（剂量累积性心肌损伤，犬最严重）。骨髓抑制。胃肠道反应（恶心、呕吐、腹泻）。脱发。局部组织坏死（外渗时）。尿液可呈红色。', '{"犬": "dose=30 mg/m²（≥10kg）或1 mg/kg（<10kg）, route=IV, frequency=每3周（累积上限180-240 mg/m²）", "猫": "dose=20-25 mg/m², route=IV, frequency=每3周（猫剂量较低）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_048', '美拉索明', 'Melarsomine', '有机砷化合物（杀心丝虫药）', '美拉索明为有机砷化合物，通过砷基团与寄生虫蛋白的巯基结合，干扰能量代谢，导致成虫死亡。对犬心丝虫成虫有高度选择性毒性，是杀灭心丝虫成虫的唯一注册药物。', '深肌肉注射（腰旁肌）。吸收后分布于肝脏和肺动脉。血浆蛋白结合率高，半衰期约3-4小时。主要经肾脏排泄。', '["犬心丝虫病（杀成虫）"]', '["严重心丝虫病（IV期，手术取虫更安全）", "妊娠", "肝肾功能严重不全"]', '["注射部位疼痛/肿胀", "肺血栓栓塞（死亡虫体）", "肝毒性", "发热/厌食"]', '注射部位疼痛和肿胀。肺血栓栓塞（虫体死亡后栓塞肺动脉，需严格限制活动）。肝毒性。肾毒性。胃肠道反应。', '{"犬": "dose=2.5 mg/kg, route=IM（深部腰肌注射）, frequency=第1天1次→第2天2次（间隔24h）= 3次注射方案", "猫": "dose=不推荐（猫对美拉索明毒性大，无安全有效剂量）, route=-, frequency=-"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_049', '伊维菌素', 'Ivermectin', '大环内酯类抗寄生虫药', '伊维菌素为大环内酯类抗寄生虫药，通过激活谷氨酸门控氯离子通道（GluCl），增加氯离子内流，导致寄生虫神经肌肉麻痹死亡。对线虫和节肢动物有广谱活性。', '口服吸收良好。血浆蛋白结合率约93%，半衰期约1-3小时。主要经肝脏代谢，经粪便排出。可穿透血脑屏障（MDR1基因缺陷犬可致严重神经毒性）。', '["心丝虫预防", "疥螨", "耳螨", "肠道线虫", "微丝蚴清除"]', '["柯利犬/牧羊犬MDR1基因突变（高剂量神经毒性）", "6周龄以下幼犬"]', '["呕吐/腹泻", "镇静/共济失调（MDR1突变犬高剂量时）", "瞳孔散大"]', 'MDR1基因缺陷犬（柯利犬等）可出现严重神经毒性：震颤、共济失调、昏迷、死亡。呕吐、腹泻。瞳孔散大。', '{"犬": "dose=6-12 μg/kg, route=PO, frequency=每月一次（心丝虫预防）", "猫": "dose=24 μg/kg, route=PO, frequency=每月一次（猫心丝虫预防剂量）"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_050', '多库酯钠/乳果糖', 'Docusate/Lactulose', '消化系统用药', '多库酯钠为粪便软化剂，通过降低粪便表面张力使水分渗入软化粪便。乳果糖为合成双糖，在结肠被细菌分解为乳酸和乙酸，增加肠腔内渗透压，保留水分，软化粪便并刺激肠蠕动。两者协同促进排便。', '两者口服后均几乎不吸收，局部作用于肠道。乳果糖在结肠被细菌发酵产酸。', '["便秘", "肝性脑病(乳果糖)"]', '["肠梗阻"]', '["腹泻", "电解质紊乱(长期使用)"]', '腹胀、腹痛。腹泻（过量时）。电解质紊乱（罕见）。', NULL);
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_051', '马罗匹坦', 'Maropitant', '止吐药', '马罗匹坦为NK-1受体拮抗剂，通过阻断P物质与NK-1受体结合，抑制呕吐中枢激活。对中枢性和外周性呕吐均有抑制作用。', '口服生物利用度约24-30%。皮下注射吸收更快。血浆蛋白结合率>99%，半衰期约8-9小时。主要经肝脏CYP450代谢。', '["各种原因呕吐", "预防晕动症"]', '["16周龄以下犬"]', '["注射部位疼痛", "一过性心动过缓"]', '注射部位疼痛。流涎、腹泻。罕见过敏反应。', '{"犬": "口服2mg/kg q24h；皮下注射1mg/kg q24h（连用最多5天）", "猫": "口服1mg/kg q24h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_052', '加巴喷丁', 'Gabapentin', '抗癫痫药/镇痛药', '加巴喷丁与电压门控钙通道α2δ亚基结合，减少钙离子内流，抑制兴奋性神经递质释放。用于神经性疼痛和辅助抗癫痫。', '口服吸收良好但剂量依赖性饱和。不与血浆蛋白结合，半衰期约3-4小时。以原形经肾脏排泄。', '["神经性疼痛", "癫痫辅助", "焦虑/应激"]', '["严重肾功能不全"]', '["镇静", "共济失调", "外周水肿"]', '镇静、共济失调。外周水肿。', '{"犬": "5-10mg/kg q8-12h", "猫": "5-10mg/kg q12h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_053', '曲马多', 'Tramadol', '镇痛药', '曲马多为弱阿片类镇痛药，双重机制：弱μ受体激动+5-HT/NE再摄取抑制。适用于中度疼痛。', '口服生物利用度约70-80%。血浆蛋白结合率约20%，半衰期约4-6小时。主要经肝脏代谢。', '["轻至中度疼痛", "慢性疼痛"]', '["MAO抑制剂合用", "癫痫患犬慎用"]', '["镇静", "恶心", "便秘", "猫可能产生兴奋而非镇静"]', '镇静、恶心、便秘。高剂量可降低癫痫阈值。', '{"犬": "2-5mg/kg q8-12h", "猫": "效果不确切，2-4mg/kg q12h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_054', '托赛米', 'Torasemide', '利尿剂', '托赛米为袢利尿剂，作用于肾小管髓袢升支粗段，抑制Na⁺/K⁺/2Cl⁻共转运体，产生强效利尿作用。与呋塞米相比，生物利用度更高且更稳定。', '口服生物利用度约80-90%（个体差异小）。血浆蛋白结合率>97%，半衰期约4-6小时。主要经肝脏代谢。', '["心力衰竭", "其他需强利尿的情况"]', '["低血容量", "低钾血症", "肝昏迷"]', '["脱水", "电解质紊乱", "肾前性氮质血症"]', '电解质紊乱（低钾、低钠、低氯性碱中毒）。脱水。耳毒性（罕见）。', '{"犬": "0.1-0.3mg/kg q24h（口服）", "猫": "0.1-0.2mg/kg q24h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_055', '贝那普利', 'Benazepril', 'ACE抑制剂', '贝那普利为ACE抑制剂，抑制血管紧张素转换酶，减少血管紧张素II生成，扩张血管，降低心脏前后负荷。', '口服后在肝脏水解为活性代谢物贝那普利拉。血浆蛋白结合率约95%，半衰期约10-12小时。', '["CKD蛋白尿", "心力衰竭", "高血压"]', '["双侧肾动脉狭窄", "妊娠"]', '["低血压", "高钾血症", "肾功能恶化"]', '低血压。高钾血症。肾功能恶化。胃肠道反应。', '犬猫：0.25-0.5mg/kg q24h');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_056', '氯吡格雷', 'Clopidogrel', '抗血小板药', '氯吡格雷为P2Y12受体拮抗剂，不可逆地抑制ADP与血小板P2Y12受体结合，阻断血小板活化和聚集。用于预防血栓形成。', '口服吸收后在肝脏转化为活性代谢物。血浆蛋白结合率约98%，半衰期约6-8小时。', '["血栓预防(猫HCM)", "动脉血栓栓塞"]', '["活动性出血", "严重肝病"]', '["出血倾向", "胃肠道不适"]', '出血风险增加。胃肠道反应。罕见血栓性血小板减少性紫癜。', '{"猫": "18.75mg/cat q24h", "犬": "1-2mg/kg q24h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_057', '阿替帕唑', 'Atipamezole', '拮抗剂', '阿替美唑为α-2受体拮抗剂，逆转美托咪定等α-2激动剂的镇静和心血管抑制效应。', '肌肉注射吸收迅速，5-10分钟起效。半衰期约1-2小时。', '["逆转α2激动剂镇静"]', NULL, '["一过性低血压", "呕吐", "兴奋"]', '短暂性低血压或高血压。兴奋、震颤。', '犬猫：给予美托咪定等量（mg:mg）IM');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_058', '氟西汀', 'Fluoxetine', '行为调节药', '氟西汀为选择性5-羟色胺再摄取抑制剂（SSRI），阻断突触前膜5-HT转运体，增加突触间隙5-HT浓度，产生抗焦虑和抗强迫作用。用于犬猫行为问题。', '口服吸收良好。血浆蛋白结合率约95%，半衰期约1-3天（活性代谢物去甲氟西汀半衰期更长）。主要经肝脏CYP2D6代谢。', '["分离焦虑", "强迫行为", "猫喷尿标记"]', '["MAO抑制剂合用", "癫痫病史"]', '["食欲下降", "镇静", "胃肠道不适"]', '胃肠道反应（厌食、呕吐）。镇静或兴奋（初期）。与MAOI合用可致5-羟色胺综合征。', '{"犬": "1-2mg/kg q24h", "猫": "0.5-1mg/kg q24h"}');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_059', '两性霉素B', 'Amphotericin B', '抗真菌药', '两性霉素B为多烯类抗真菌药，与真菌细胞膜上的麦角固醇结合，形成膜孔道，导致细胞内重要物质外漏和细胞死亡。对多种深部真菌有杀菌作用。', '口服几乎不吸收（仅用于肠道真菌感染）。静脉给药后血浆蛋白结合率>90%，半衰期约15天。主要经肝脏代谢。', '["全身性真菌感染"]', '["严重肾功能不全(普通剂型)"]', '["肾毒性(普通剂型)", "输液反应", "低钾血症"]', '肾毒性（最常见且严重，可致急性肾损伤）。输液反应（寒战、发热）。低钾血症。贫血。', '犬：普通剂型0.25-0.5mg/kg IV 隔日；脂质体剂型1-3mg/kg IV 每周2-3次');
INSERT INTO drugs (id, name_zh, name_en, drug_class, mechanism_of_action, pk_pd, indications, contraindications, side_effects, adverse_mechanism, species_dosing) VALUES ('drug_060', '伊曲康唑', 'Itraconazole', '抗真菌药', '伊曲康唑为三唑类抗真菌药，抑制14α-去甲基酶，阻断麦角固醇合成。对皮肤癣菌、念珠菌、曲霉菌等均有活性。', '口服吸收受胃酸和食物影响。高度亲脂性。血浆蛋白结合率>99%，半衰期约12-15小时。主要经肝脏CYP450代谢。', '["皮肤真菌病", "全身性真菌感染"]', '["严重肝病", "妊娠"]', '["肝毒性", "食欲下降", "呕吐"]', '胃肠道反应。肝毒性。药物相互作用（CYP450抑制）。', '{"犬": "5-10mg/kg q24h", "猫": "5-10mg/kg q24h（口服液）"}');
