INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_014', 'drug_003', 'first', '犬', '呋塞米减轻肺水肿/全身淤血');
INSERT INTO disease_treatment (disease_id,drug_id,line,species,notes) VALUES ('dis_014', 'drug_006', 'first', '犬', '匹莫苯丹改善收缩功能（DCM核心用药）');
